// Quiz content for Cours37 — Analyse avancée : Schenker et analyse motivique

export interface Question { q: string; opts: string[]; a: number; fb: string; }
export interface Cours37Locale { questions: Question[]; }

const questionsFr: Question[] = [
  // ── Analyse schenkérienne (20 questions) ──────────────────────────────────

  { q: "Qu'est-ce que l'Ursatz selon Heinrich Schenker ?", opts: ["Un motif de 4 notes en fugue", "La structure harmonique fondamentale de toute musique tonale : Urlinie (ligne mélodique descendante 5̂–1̂) + Bassbrechung (arpeggement de basse I–V–I)", "L'accord de tonique dans une cadence", "Le premier thème d'une forme sonate"], a: 1, fb: "L'Ursatz ('structure fondamentale') est la charpente harmonique de toute musique tonale selon Schenker. Elle comprend l'Urlinie (ligne mélodique descendante du 5e, 3e ou 8e degré vers la tonique) et le Bassbrechung (basse qui arpège I–V–I). Tout le reste de la musique est 'prolongation' ou 'ornement' de cet Ursatz sous-jacent." },
  { q: "Qu'est-ce que la 'prolongation harmonique' dans l'analyse schenkérienne ?", opts: ["Rallonger la durée d'un accord", "L'élaboration d'une harmonie structurelle par des harmonies intermédiaires — la tonique 'dure' harmoniquement même quand des accords non-toniques la décorent temporairement", "Une pédale de basse", "Un trémolo sur un accord"], a: 1, fb: "La prolongation signifie qu'une harmonie structurelle (généralement I ou V) continue d'exercer son influence pendant que des harmonies de passage ou des broderies l'ornementent en surface. Sur 32 mesures apparemment variées, l'analyse peut montrer que la tonique est 'prolongée' — les changements de surface ne modifient pas la structure." },
  { q: "Quels sont les 4 niveaux de réduction dans l'analyse schenkérienne ?", opts: ["Niveau A (majeur), B (mineur), C (chromantique), D (diatonique)", "Niveau 4 (surface, tous accords), 3 (intermédiaire), 2 (régions tonales), 1 (Urlinie/structure)", "Niveau 1 (notes), 2 (mesures), 3 (phrases), 4 (sections)", "Niveau I, V, II, IV selon les fonctions harmoniques"], a: 1, fb: "Les 4 niveaux schenkériens : Niveau 4 (Vordergrund) = surface : tous les accords mesure par mesure. Niveau 3 (Mittelgrund proche) : fonctions harmoniques principales. Niveau 2 (Mittelgrund profond) : régions tonales et prolongations. Niveau 1 (Hintergrund) : Urlinie + Bassbrechung seulement. Chaque réduction révèle une couche de sens structurel." },
  { q: "Qu'est-ce que le 'Vordergrund' dans l'analyse schenkérienne ?", opts: ["La structure la plus profonde", "Le premier plan — la surface musicale avec tous ses détails : mélodie, accords, ornements, rythme", "La partie de piano du premier plan", "Le motif principal"], a: 0, fb: "Vordergrund = 'premier plan' = la surface musicale complète telle qu'elle est jouée. Tout ce qu'on entend : ornements, notes de passage, arpèges, broderies, retards, appogiatures. C'est le point de départ de l'analyse — on réduit ensuite pour découvrir les niveaux plus profonds." },
  { q: "Qu'est-ce que le 'Hintergrund' dans l'analyse schenkérienne ?", opts: ["L'arrière-plan orchestral", "L'arrière-plan structurel — le niveau le plus profond : Urlinie + Bassbrechung. La charpente harmonique sous toute l'ornement de surface", "La partie de basse uniquement", "La forme globale (sonate, rondo)"], a: 1, fb: "Hintergrund = 'arrière-plan' = la structure fondamentale. C'est l'Ursatz : la ligne mélodique descendante (Urlinie, du 5e, 3e ou 8e vers la tonique) soutenue par la basse arpeggée I–V–I. Ce niveau révèle comment toute la complexité de surface est une ornementalisation d'une structure harmonique simple." },
  { q: "Quelle est la signification du signe 5̂ (chapeau sur le chiffre 5) dans la notation schenkérienne ?", opts: ["Le 5e accord du cycle des quintes", "Le 5e degré de la gamme vu comme note de l'Urlinie — point de départ fréquent de la ligne structurelle descendante", "La 5e mesure de l'œuvre", "L'accord de dominante"], a: 1, fb: "La notation ̂ (chapeau) indique un degré scalaire structurel de l'Urlinie. 5̂ = le 5e degré de la gamme comme note de départ de la ligne fondamentale. L'Urlinie commence typiquement sur 5̂, 3̂ ou 8̂ et descend stepwise jusqu'à 1̂ (la tonique). 5̂–4̂–3̂–2̂–1̂ est l'Urlinie à 5 notes la plus complète." },
  { q: "Qu'est-ce qu'une 'note de broderie' (Neighbor note) dans l'analyse schenkérienne ?", opts: ["Une note ajoutée pour la virtuosité pianistique", "Un ornement qui s'éloigne d'une note structurelle d'un degré vers le haut ou le bas, puis y revient — la note structurelle 'entoure' l'ornement", "Une note appartenant au contre-sujet d'une fugue", "Une note chromatique"], a: 1, fb: "La note de broderie (Nebennote) est une ornementalisation : la note structurelle part vers le degré adjacent (supérieur ou inférieur) puis revient. Do–Ré–Do : le Ré est une broderie supérieure du Do structurel. Dans la réduction schenkérienne, les broderies disparaissent aux niveaux plus profonds pour révéler la note structurelle." },
  { q: "Qu'est-ce qu'une 'note de passage' (Passing note) dans l'analyse schenkérienne ?", opts: ["Une note qui modifie le tempo", "Une note qui remplit l'espace entre deux notes structurelles, généralement par mouvement conjoint", "Une note jouée fortissimo", "Une note du contre-sujet"], a: 1, fb: "La note de passage (Durchgangsnote) relie deux notes structurelles par mouvement conjoint : Do–Ré–Mi, si Do et Mi sont structurelles, le Ré est une note de passage. Dans la réduction, les notes de passage disparaissent pour révéler la connexion directe entre les notes structurelles. Elles créent le mouvement mélodique de surface." },
  { q: "Heinrich Schenker était-il un compositeur ou un théoricien ?", opts: ["Uniquement compositeur (aucune théorie)", "Principalement théoricien et critique musical — il a composé peu mais a développé la plus grande théorie analytique du XXe siècle", "Un interprète de piano virtuose sans théorie", "Un élève de Brahms qui n'a publié aucun texte"], a: 1, fb: "Heinrich Schenker (1868–1935) était théoricien, critique musical et professeur viennois. Il a étudié avec Brahms et développé sa théorie analytique dans plusieurs ouvrages monumentaux : Harmonielehre (1906), Counterpoint (1910–1922) et Der freie Satz (1935, posthume). Sa méthode analytique est enseignée dans les universités du monde entier." },
  { q: "Pourquoi l'analyse schenkérienne est-elle parfois critiquée ?", opts: ["Parce qu'elle est trop simple", "Parce qu'elle s'applique difficilement à la musique non-tonale (atonale, modale) et parce que ses 'lois' reflètent parfois le goût personnel de Schenker plus qu'une vérité universelle", "Parce qu'elle ne convient qu'à Bach", "Parce qu'elle est trop quantitative et mathématique"], a: 1, fb: "L'analyse schenkérienne a des limites : 1/ Elle ne s'applique qu'à la musique tonale (pas atonale ni modale). 2/ Les choix de réduction sont parfois subjectifs. 3/ Schenker lui-même avait des goûts esthétiques marqués (adorait Brahms, détestait Debussy) qui influençaient ses analyses. Ces critiques n'enlèvent rien à la puissance de l'outil pour la musique tonale." },

  { q: "Quelle est la formule de l'Urlinie la plus fréquente dans les pièces tonales courtes ?", opts: ["8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (octave complète)", "3̂–2̂–1̂ (ligne descendante de la tierce à la tonique)", "5̂–4̂–3̂ (descente partielle)", "1̂–2̂–1̂ (broderie de tonique)"], a: 1, fb: "L'Urlinie 3̂–2̂–1̂ est la plus fréquente dans les pièces courtes et simples : la mélodie structurelle descend du 3e degré (médiante) vers la tonique en passant par la sus-tonique. C'est l'Urlinie de nombreux préludes de Bach, de mélodies folkloriques et de pièces classiques courtes. L'Urlinie 5̂–1̂ est plus ample, typique des sonates et symphonies." },
  { q: "Qu'est-ce que le 'Kopfton' dans l'analyse schenkérienne ?", opts: ["La note la plus aiguë de l'œuvre", "La note de départ de l'Urlinie — le point depuis lequel la ligne mélodique structurelle descend vers la tonique", "Le premier accord de l'exposition", "La note pivot d'une modulation"], a: 1, fb: "Kopfton = 'note tête'. C'est la note de départ de l'Urlinie, généralement 3̂, 5̂ ou 8̂. Toute la musique peut être vue comme l'élaboration du chemin entre le Kopfton et la tonique finale (1̂). Identifier le Kopfton est une étape clé de l'analyse — il détermine quelle version de l'Urlinie est à l'œuvre et comment la mélodie de surface 'descend' structurellement." },
  { q: "Comment la réduction schenkérienne aide-t-elle à comprendre une modulation ?", opts: ["Elle montre que toutes les modulations sont fausses", "Elle révèle si la modulation est structurelle (change le niveau 2) ou de surface (ornementale, changement temporaire qui revient au niveau 1 identique)", "Elle supprime les modulations de l'analyse", "Elle transforme toutes les modulations en emprunts modaux"], a: 1, fb: "La réduction schenkérienne distingue modulation structurelle (le niveau 2 change de région tonale — le Mittelgrund est modifié) et modulation de surface (ornementale — le niveau 1 revient au même Hintergrund). Beaucoup de modulations apparentes dans Beethoven ou Mozart sont en fait des prolongations ornementales qui reviennent à la tonalité de départ sans changer la structure profonde." },

  // ── Analyse motivique (12 questions) ──────────────────────────────────────

  { q: "Quel est le motif de base de la 5e Symphonie de Beethoven op.67 ?", opts: ["Do–Ré–Mi–Fa (gamme ascendante de 4 notes)", "Sol–Sol–Sol–Mib (3 croches + noire : rythme court-court-court-long)", "Fa–Mi–Ré–Do (gamme descendante)", "La–Sol–Fa–Mi (tétracorde descendant)"], a: 1, fb: "Le motif initial de la 5e Symphonie est Sol–Sol–Sol–Mib — 3 croches + 1 noire (rythme « ta-ta-ta-TUM »). Ce motif de 4 notes n'est pas qu'un thème d'introduction : c'est le matériau générateur de l'œuvre entière. Beethoven le transforme, l'augmente, l'inverse, le fragmente sur les 4 mouvements. C'est le motif le plus célèbre de toute la littérature musicale." },
  { q: "Comment le motif Sol–Sol–Sol–Mib est-il transformé dans le 2e mouvement de la 5e Symphonie ?", opts: ["Il disparaît complètement", "Il est transformé en mode majeur avec un contour mélodique différent mais le rythme court-court-court-long préservé", "Il est joué identique mais transposé", "Il est inversé melodiquement"], a: 1, fb: "Dans le 2e mouvement (Andante con moto), le motif rythmique court-court-court-long est préservé mais intégré dans une mélodie lyrique majeure très différente de la brutalité du 1er mouvement. Le contour mélodique change, mais l'identité rythmique permet de reconnaître le motif transformé. Beethoven montre que le motif transcende ses qualités de surface." },
  { q: "Qu'est-ce que la 'fragmentation' d'un motif ?", opts: ["Supprimer le motif complètement", "Réduire le motif à un de ses éléments constitutifs — jouer seulement le rythme, ou seulement les 2 premières notes, pour créer de la tension ou de l'attente", "Jouer le motif en augmentation", "Combiner deux motifs différents"], a: 1, fb: "La fragmentation décompose le motif en ses éléments. Dans la 5e Symphonie, développement du 1er mouvement, Beethoven fragmente le motif à une seule quarte (Sol–Mib) puis à une seule noire (juste le rythme, plus de mélodie). Cette réduction progressive crée une tension extrême — le motif est 'déchiré' avant d'être réassemblé dans la réexposition." },
  { q: "Qu'est-ce que la 'séquence' motivique comme technique de développement ?", opts: ["Répéter le motif sur la même hauteur", "Répéter le motif en le transposant à intervalles réguliers — le même contour mélodique et rythmique monte ou descend par degrés", "Inverser le motif mélodiquement", "Augmenter la durée de toutes les notes"], a: 1, fb: "La séquence est la répétition d'un motif transposé à intervalles réguliers. Motif sur Do, puis sur Si, puis sur La (séquence descendante par degrés). La séquence crée un mouvement directionnel fort — elle 'tire' la musique vers une cible. Bach, Handel, Vivaldi et Beethoven l'utilisent massivement pour les transitions et les développements." },
  { q: "Quel est le 'motif générateur' dans les Quatuors à cordes de Brahms op.51 ?", opts: ["Une tierce majeure ascendante", "Un intervalle de seconde (souvent mineure) qui se retrouve sous toutes les formes (ascendant, descendant, augmenté, inversé) dans toute l'œuvre", "Un rythme de trois croches", "Un accord de 7e diminuée"], a: 1, fb: "Dans l'opus 51 de Brahms, un intervalle de seconde structure chaque mouvement. L'analyse révèle que le même intervalle (Sol–Lab, par exemple) réapparaît partout : dans le sujet principal, le contre-sujet, la mélodie du 2e mouvement, le scherzo. C'est la 'motif économie' de Brahms — composer un maximum avec un minimum de matériau." },
  { q: "Comment Beethoven transforme-t-il le motif de la 5e Symphonie dans le 4e mouvement final ?", opts: ["Il le supprime pour terminer sur un thème nouveau", "Il le présente triomphalement en majeur, augmenté et glorifié — la 'victoire' de la tonalité mineure vers majeure", "Il le joue exactement comme au début", "Il l'inverse mélodiquement"], a: 1, fb: "Le 4e mouvement (Allegro, Do majeur) est la 'réponse' au 1er (Do mineur). Le motif Sol–Sol–Sol–Mib, d'abord sombre et menaçant, devient triomphant en majeur avec les cuivres pleine puissance. La transformation modale (mineur → majeur) et dynamique (forte dramatique → fortissimo victorieux) signifie la résolution du conflit de toute la symphonie." },
  { q: "Qu'est-ce que l'analyse 'voice leading' (conduite des voix) dans un contexte analytique (pas compositionnel) ?", opts: ["Identifier les voix d'une fugue", "Tracer comment chaque voix d'un accord se déplace vers les notes de l'accord suivant — identifier les mouvements conjoints, les sauts, les notes tenues et les notes communes", "Analyser la tessiture des chanteurs", "Compter le nombre de voix dans une fugue"], a: 1, fb: "L'analyse de voice leading (conduite des voix) suit chaque ligne individuelle d'une progression harmonique. Dans un I–IV–V–I, comment le soprano se déplace-t-il ? L'alto ? La basse ? On trace les notes communes (liées), les mouvements conjoints (fluides) et les sauts. Cette analyse révèle la logique linéaire sous-jacente à la progression harmonique." },
  { q: "Quelle est la méthode en 4 étapes pour réaliser une analyse schenkérienne d'une pièce ?", opts: ["1-Écouter 2-Jouer 3-Mémoriser 4-Interpréter", "1-Identifier les cadences structurelles 2-Tracer la basse structurelle 3-Identifier les notes mélodiques structurelles 4-Réduire progressivement jusqu'à l'Ursatz", "1-Analyser les accords 2-Nommer les fonctions 3-Identifier la tonalité 4-Écrire le résumé", "1-Identifier le sujet 2-La réponse 3-Le contre-sujet 4-Les épisodes"], a: 1, fb: "La méthode analytique schenkérienne : 1/ Identifier les cadences structurelles (V→I authentiques) qui délimitent les sections ; 2/ Tracer la ligne de basse structurelle (fondamentales des harmonies importantes) ; 3/ Identifier les notes mélodiques structurelles (notes tenues longues, notes cadentielles) ; 4/ Réduire progressivement jusqu'à l'Ursatz simple." },
  { q: "Comment la notation schenkérienne distingue-t-elle notes structurelles et notes ornementales ?", opts: ["Par la couleur des notes (noires vs blanches)", "Par l'usage de têtes de note avec hampes (notes structurelles) vs sans hampes (ornementales), plus des liaisons pour les prolongations", "Par la position sur la portée (graves vs aiguës)", "Par le chiffrage romain (I, V) vs arabe (1, 2)"], a: 1, fb: "La notation schenkérienne utilise un système graphique spécifique : notes structurelles = têtes de notes plongeantes ou avec hampes ; notes ornementales = sans hampe ou en petite taille ; liaisons courbes = prolongations harmoniques ; slurs (liaisons mélodiques) = connections entre notes structurelles. Le système visuel révèle la hiérarchie analytique d'un coup d'œil." },
  { q: "Pourquoi l'analyse motivique de la 5e Symphonie est-elle plus informative que l'analyse accord-par-accord ?", opts: ["L'analyse d'accords est plus rapide à réaliser", "L'analyse motivique révèle la cohérence architecturale sur 4 mouvements — comment un seul motif de 4 notes structure 35 minutes de musique, ce qu'une analyse d'accords mesure-par-mesure ne peut pas montrer", "L'analyse motivique est moins précise mais plus artistique", "Les deux analyses donnent exactement les mêmes informations"], a: 1, fb: "L'analyse accord-par-accord décrit la surface harmonique de chaque mesure mais ne révèle pas comment ces mesures sont reliées. L'analyse motivique montre la cohérence : le motif Sol–Sol–Sol–Mib revient sous 15 formes différentes en 35 minutes. C'est cette unité structurelle profonde qui rend la 5e Symphonie une œuvre unifiée plutôt qu'une collection de thèmes." },
  { q: "Qu'est-ce que la 'diminution' d'un motif comme technique de développement ?", opts: ["Jouer le motif plus doucement (diminuendo)", "Jouer le motif en valeurs rythmiques réduites — chaque noire devient croche, chaque croche devient double-croche", "Réduire le nombre de notes du motif", "Transposer le motif plus bas"], a: 1, fb: "La diminution est l'inverse de l'augmentation : le motif est joué en valeurs rythmiques réduites. Un motif de noires devient des croches, des croches deviennent des doubles-croches. L'effet est d'accélérer et d'alléger le motif — créer de l'agitation ou de la brillance là où l'augmentation crée de la gravité. Technique utilisée dans les développements pour accélérer progressivement." },
  { q: "Quel est l'apport de l'analyse motivique par rapport à l'analyse formelle (sonate, rondo) ?", opts: ["L'analyse formelle est plus complète — elle remplace l'analyse motivique", "L'analyse formelle décrit la structure externe (A-B-A, exposition-développement-réexposition) ; l'analyse motivique révèle la substance interne (comment un motif génère le contenu de chaque section)", "Elles sont identiques et indifférentes", "L'analyse motivique ne s'applique qu'aux pièces modernes"], a: 1, fb: "L'analyse formelle identifie les 'cases' de la forme : exposition, développement, réexposition, coda. L'analyse motivique remplit ces cases avec du sens : ce qui est développé dans le développement (quels motifs, quelles transformations), pourquoi la réexposition est différente de l'exposition (quels motifs ont évolué). Les deux analyses sont complémentaires — ni l'une ni l'autre n'est suffisante seule." },
];

const questionsEn: Question[] = [
  { q: "What is the Ursatz according to Heinrich Schenker?", opts: ["A 4-note fugue motif", "The fundamental harmonic structure of all tonal music: Urlinie (descending melodic line 5̂–1̂) + Bassbrechung (bass arpeggiation I–V–I)", "The tonic chord in a cadence", "The first theme of a sonata form"], a: 1, fb: "The Ursatz ('fundamental structure') is the harmonic framework of all tonal music according to Schenker. It comprises the Urlinie (descending melodic line from the 5th, 3rd or 8th scale degree to the tonic) and the Bassbrechung (bass arpeggiating I–V–I). Everything else in the music is 'prolongation' or 'ornamentation' of this underlying Ursatz." },
  { q: "What is 'harmonic prolongation' in Schenkerian analysis?", opts: ["Extending the duration of a chord", "The elaboration of a structural harmony by intermediate harmonies — the tonic 'persists' harmonically even when non-tonic chords temporarily decorate it", "A bass pedal point", "A tremolo on a chord"], a: 1, fb: "Prolongation means that a structural harmony (usually I or V) continues to exert its influence while passing harmonies or embellishments ornament it on the surface. Across 32 apparently varied measures, analysis can show that the tonic is 'prolonged' — surface changes do not alter the deep structure." },
  { q: "What are the 4 levels of reduction in Schenkerian analysis?", opts: ["Level A (major), B (minor), C (chromatic), D (diatonic)", "Level 4 (surface, all chords), 3 (intermediate), 2 (tonal regions), 1 (Urlinie/structure)", "Level 1 (notes), 2 (measures), 3 (phrases), 4 (sections)", "Levels I, V, II, IV according to harmonic functions"], a: 1, fb: "The 4 Schenkerian levels: Level 4 (Vordergrund) = surface: all chords measure by measure. Level 3 (near Mittelgrund): main harmonic functions. Level 2 (deep Mittelgrund): tonal regions and prolongations. Level 1 (Hintergrund): Urlinie + Bassbrechung only. Each reduction reveals a layer of structural meaning." },
  { q: "What is the 'Vordergrund' in Schenkerian analysis?", opts: ["The deepest structure", "The foreground — the musical surface with all its details: melody, chords, ornaments, rhythm", "The piano part in the foreground", "The main motif"], a: 0, fb: "Vordergrund = 'foreground' = the complete musical surface as performed. Everything heard: ornaments, passing notes, arpeggios, neighbor notes, suspensions, appoggiaturas. This is the starting point of analysis — one then reduces to discover deeper levels." },
  { q: "What is the 'Hintergrund' in Schenkerian analysis?", opts: ["The orchestral background", "The structural background — the deepest level: Urlinie + Bassbrechung. The harmonic framework beneath all surface ornamentation", "The bass part only", "The overall form (sonata, rondo)"], a: 1, fb: "Hintergrund = 'background' = the fundamental structure. This is the Ursatz: the descending melodic line (Urlinie, from the 5th, 3rd or 8th to the tonic) supported by the arpeggiated bass I–V–I. This level reveals how all surface complexity is an ornamentation of a simple harmonic structure." },
  { q: "What is the meaning of the symbol 5̂ (hat over the number 5) in Schenkerian notation?", opts: ["The 5th chord in the cycle of fifths", "The 5th scale degree as an Urlinie note — a frequent starting point of the descending structural line", "The 5th measure of the work", "The dominant chord"], a: 1, fb: "The ̂ (caret/hat) notation indicates a structural scale degree of the Urlinie. 5̂ = the 5th scale degree as the starting note of the fundamental line. The Urlinie typically begins on 5̂, 3̂ or 8̂ and descends stepwise to 1̂ (the tonic). 5̂–4̂–3̂–2̂–1̂ is the most complete 5-note Urlinie." },
  { q: "What is a 'neighbor note' (Nebennote) in Schenkerian analysis?", opts: ["A note added for pianistic virtuosity", "An ornament that moves away from a structural note by one degree upward or downward, then returns — the structural note 'surrounds' the ornament", "A note belonging to the countersubject of a fugue", "A chromatic note"], a: 1, fb: "The neighbor note (Nebennote) is an ornamentation: the structural note moves to the adjacent degree (upper or lower) then returns. C–D–C: the D is an upper neighbor of structural C. In Schenkerian reduction, neighbor notes disappear at deeper levels to reveal the structural note." },
  { q: "What is a 'passing note' (Durchgangsnote) in Schenkerian analysis?", opts: ["A note that changes the tempo", "A note that fills the space between two structural notes, generally by stepwise motion", "A note played fortissimo", "A note from the countersubject"], a: 1, fb: "The passing note (Durchgangsnote) connects two structural notes by stepwise motion: C–D–E, if C and E are structural, D is a passing note. In the reduction, passing notes disappear to reveal the direct connection between structural notes. They create surface melodic motion." },
  { q: "Was Heinrich Schenker a composer or a theorist?", opts: ["Solely a composer (no theory)", "Primarily a music theorist and critic — he composed little but developed the greatest analytical theory of the 20th century", "A virtuoso piano performer with no theory", "A student of Brahms who published no texts"], a: 1, fb: "Heinrich Schenker (1868–1935) was a Viennese theorist, music critic and teacher. He studied with Brahms and developed his analytical theory in several monumental works: Harmonielehre (1906), Counterpoint (1910–1922) and Der freie Satz (1935, posthumous). His analytical method is taught at universities worldwide." },
  { q: "Why is Schenkerian analysis sometimes criticized?", opts: ["Because it is too simple", "Because it applies with difficulty to non-tonal music (atonal, modal) and because its 'laws' sometimes reflect Schenker's personal taste more than a universal truth", "Because it only suits Bach", "Because it is too quantitative and mathematical"], a: 1, fb: "Schenkerian analysis has limitations: 1/ It only applies to tonal music (not atonal or modal). 2/ Reduction choices are sometimes subjective. 3/ Schenker himself had strong aesthetic preferences (adored Brahms, disliked Debussy) that influenced his analyses. These criticisms do not diminish the power of the tool for tonal music." },
  { q: "What is the most frequent Urlinie formula in short tonal pieces?", opts: ["8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (complete octave)", "3̂–2̂–1̂ (descending line from the third to the tonic)", "5̂–4̂–3̂ (partial descent)", "1̂–2̂–1̂ (tonic neighbor)"], a: 1, fb: "The Urlinie 3̂–2̂–1̂ is the most frequent in short, simple pieces: the structural melody descends from the 3rd degree (mediant) to the tonic passing through the supertonic. This is the Urlinie of many Bach preludes, folk melodies and short classical pieces. The Urlinie 5̂–1̂ is broader, typical of sonatas and symphonies." },
  { q: "What is the 'Kopfton' in Schenkerian analysis?", opts: ["The highest note of the work", "The starting note of the Urlinie — the point from which the structural melodic line descends to the tonic", "The first chord of the exposition", "The pivot note of a modulation"], a: 1, fb: "Kopfton = 'head tone'. It is the starting note of the Urlinie, usually 3̂, 5̂ or 8̂. All the music can be seen as the elaboration of the path between the Kopfton and the final tonic (1̂). Identifying the Kopfton is a key step in analysis — it determines which version of the Urlinie is at work and how the surface melody 'descends' structurally." },
  { q: "How does Schenkerian reduction help understand a modulation?", opts: ["It shows that all modulations are false", "It reveals whether the modulation is structural (changes level 2) or surface (ornamental, a temporary change that returns to the same level 1)", "It removes modulations from analysis", "It transforms all modulations into modal borrowings"], a: 1, fb: "Schenkerian reduction distinguishes structural modulation (level 2 changes tonal region — the Mittelgrund is modified) from surface modulation (ornamental — level 1 returns to the same Hintergrund). Many apparent modulations in Beethoven or Mozart are in fact ornamental prolongations that return to the opening tonality without altering the deep structure." },
  { q: "What is the basic motif of Beethoven's Symphony No. 5 op. 67?", opts: ["C–D–E–F (ascending 4-note scale)", "G–G–G–Eb (3 eighth notes + quarter note: short-short-short-long rhythm)", "F–E–D–C (descending scale)", "A–G–F–E (descending tetrachord)"], a: 1, fb: "The opening motif of the 5th Symphony is G–G–G–Eb — 3 eighth notes + 1 quarter note (the 'ta-ta-ta-TUM' rhythm). This 4-note motif is not merely an introductory theme: it is the generative material of the entire work. Beethoven transforms it, augments it, inverts it and fragments it across all 4 movements. It is the most famous motif in all musical literature." },
  { q: "How is the G–G–G–Eb motif transformed in the 2nd movement of Symphony No. 5?", opts: ["It disappears completely", "It is transformed into major mode with a different melodic contour but the short-short-short-long rhythm preserved", "It is played identically but transposed", "It is melodically inverted"], a: 1, fb: "In the 2nd movement (Andante con moto), the short-short-short-long rhythmic motif is preserved but integrated into a very different lyrical major melody compared to the brutality of the 1st movement. The melodic contour changes, but the rhythmic identity allows the transformed motif to be recognized. Beethoven shows that the motif transcends its surface qualities." },
  { q: "What is 'fragmentation' of a motif?", opts: ["Deleting the motif completely", "Reducing the motif to one of its constituent elements — playing only the rhythm, or only the first 2 notes, to create tension or anticipation", "Playing the motif in augmentation", "Combining two different motifs"], a: 1, fb: "Fragmentation decomposes the motif into its elements. In the 5th Symphony development of the 1st movement, Beethoven fragments the motif to a single fourth (G–Eb), then to a single quarter note (just the rhythm, no melody). This progressive reduction creates extreme tension — the motif is 'torn apart' before being reassembled in the recapitulation." },
  { q: "What is a motivic 'sequence' as a development technique?", opts: ["Repeating the motif at the same pitch", "Repeating the motif by transposing it at regular intervals — the same melodic and rhythmic contour rises or descends by steps", "Inverting the motif melodically", "Augmenting the duration of all notes"], a: 1, fb: "A sequence is the repetition of a motif transposed at regular intervals. Motif on C, then on B, then on A (descending stepwise sequence). The sequence creates strong directional motion — it 'pulls' the music toward a target. Bach, Handel, Vivaldi and Beethoven use it extensively for transitions and developments." },
  { q: "What is the 'generating motif' in Brahms's String Quartets op. 51?", opts: ["An ascending major third", "A second interval (often minor) found in all forms (ascending, descending, augmented, inverted) throughout the entire work", "A three-eighth-note rhythm", "A diminished 7th chord"], a: 1, fb: "In Brahms's op. 51, a second interval structures every movement. Analysis reveals that the same interval (G–Ab, for example) reappears everywhere: in the main subject, the countersubject, the 2nd-movement melody, the scherzo. This is Brahms's 'motivic economy' — composing the maximum with the minimum of material." },
  { q: "How does Beethoven transform the 5th Symphony motif in the 4th final movement?", opts: ["He removes it to end with a new theme", "He presents it triumphantly in major, augmented and glorified — the 'victory' from minor to major tonality", "He plays it exactly as at the opening", "He inverts it melodically"], a: 1, fb: "The 4th movement (Allegro, C major) is the 'answer' to the 1st (C minor). The G–G–G–Eb motif, first dark and threatening, becomes triumphant in major with full-power brass. The modal transformation (minor → major) and dynamic shift (dramatic forte → victorious fortissimo) signifies the resolution of the conflict of the entire symphony." },
  { q: "What is 'voice leading' analysis in an analytical (not compositional) context?", opts: ["Identifying the voices of a fugue", "Tracing how each voice of a chord moves to the notes of the next chord — identifying stepwise motion, leaps, held notes and common tones", "Analyzing the tessitura of singers", "Counting the number of voices in a fugue"], a: 1, fb: "Voice leading analysis follows each individual line in a harmonic progression. In a I–IV–V–I, how does the soprano move? The alto? The bass? One traces common tones (tied), stepwise motion (smooth) and leaps. This analysis reveals the underlying linear logic beneath the harmonic progression." },
  { q: "What is the 4-step method for carrying out a Schenkerian analysis of a piece?", opts: ["1-Listen 2-Play 3-Memorize 4-Interpret", "1-Identify structural cadences 2-Trace the structural bass 3-Identify structural melodic notes 4-Reduce progressively to the Ursatz", "1-Analyze chords 2-Name functions 3-Identify the tonality 4-Write the summary", "1-Identify the subject 2-The answer 3-The countersubject 4-The episodes"], a: 1, fb: "The Schenkerian analytical method: 1/ Identify structural cadences (authentic V→I) that delimit sections; 2/ Trace the structural bass line (roots of important harmonies); 3/ Identify structural melodic notes (long sustained notes, cadential notes); 4/ Reduce progressively to the simple Ursatz." },
  { q: "How does Schenkerian notation distinguish structural notes from ornamental notes?", opts: ["By note color (black vs white)", "By the use of note heads with stems (structural notes) vs without stems (ornamental), plus slurs for prolongations", "By position on the staff (low vs high)", "By Roman numeral (I, V) vs Arabic (1, 2) labeling"], a: 1, fb: "Schenkerian notation uses a specific graphic system: structural notes = note heads with stems; ornamental notes = stemless or small-sized; curved slurs = harmonic prolongations; melodic slurs = connections between structural notes. The visual system reveals the analytical hierarchy at a glance." },
  { q: "Why is motivic analysis of the 5th Symphony more informative than chord-by-chord analysis?", opts: ["Chord analysis is faster to carry out", "Motivic analysis reveals the architectural coherence across 4 movements — how a single 4-note motif structures 35 minutes of music, which a measure-by-measure chord analysis cannot show", "Motivic analysis is less precise but more artistic", "Both analyses yield exactly the same information"], a: 1, fb: "Chord-by-chord analysis describes the harmonic surface of each measure but does not reveal how those measures are connected. Motivic analysis shows the coherence: the G–G–G–Eb motif returns in 15 different forms over 35 minutes. This deep structural unity is what makes the 5th Symphony a unified work rather than a collection of themes." },
  { q: "What is 'diminution' of a motif as a development technique?", opts: ["Playing the motif more softly (diminuendo)", "Playing the motif in reduced rhythmic values — each quarter note becomes an eighth note, each eighth note becomes a sixteenth note", "Reducing the number of notes in the motif", "Transposing the motif lower"], a: 1, fb: "Diminution is the opposite of augmentation: the motif is played in reduced rhythmic values. A motif of quarter notes becomes eighth notes, eighth notes become sixteenth notes. The effect is to accelerate and lighten the motif — creating agitation or brilliance where augmentation creates gravity. Used in developments to accelerate progressively." },
  { q: "What does motivic analysis contribute compared to formal analysis (sonata, rondo)?", opts: ["Formal analysis is more complete — it replaces motivic analysis", "Formal analysis describes the external structure (A-B-A, exposition-development-recapitulation); motivic analysis reveals the internal substance (how a motif generates the content of each section)", "They are identical and interchangeable", "Motivic analysis only applies to modern pieces"], a: 1, fb: "Formal analysis identifies the 'boxes' of the form: exposition, development, recapitulation, coda. Motivic analysis fills those boxes with meaning: what is developed in the development (which motifs, which transformations), why the recapitulation differs from the exposition (which motifs have evolved). The two analyses are complementary — neither alone is sufficient." },
];

const questionsEs: Question[] = [
  { q: "¿Qué es el Ursatz según Heinrich Schenker?", opts: ["Un motivo de 4 notas en una fuga", "La estructura armónica fundamental de toda la música tonal: Urlinie (línea melódica descendente 5̂–1̂) + Bassbrechung (arpegiado de bajo I–V–I)", "El acorde de tónica en una cadencia", "El primer tema de una forma sonata"], a: 1, fb: "El Ursatz ('estructura fundamental') es el esqueleto armónico de toda la música tonal según Schenker. Comprende la Urlinie (línea melódica descendente desde el 5.º, 3.er u 8.º grado hasta la tónica) y el Bassbrechung (bajo que arpegía I–V–I). Todo lo demás en la música es 'prolongación' u 'ornamento' de este Ursatz subyacente." },
  { q: "¿Qué es la 'prolongación armónica' en el análisis schenkeriano?", opts: ["Alargar la duración de un acorde", "La elaboración de una armonía estructural mediante armonías intermedias — la tónica 'persiste' armónicamente incluso cuando acordes no tonales la decoran temporalmente", "Un pedal de bajo", "Un trémolo sobre un acorde"], a: 1, fb: "La prolongación significa que una armonía estructural (generalmente I o V) continúa ejerciendo su influencia mientras armonías de paso o bordaduras la ornamenten en la superficie. En 32 compases aparentemente variados, el análisis puede mostrar que la tónica está 'prolongada' — los cambios de superficie no alteran la estructura profunda." },
  { q: "¿Cuáles son los 4 niveles de reducción en el análisis schenkeriano?", opts: ["Nivel A (mayor), B (menor), C (cromático), D (diatónico)", "Nivel 4 (superficie, todos los acordes), 3 (intermedio), 2 (regiones tonales), 1 (Urlinie/estructura)", "Nivel 1 (notas), 2 (compases), 3 (frases), 4 (secciones)", "Niveles I, V, II, IV según las funciones armónicas"], a: 1, fb: "Los 4 niveles schenkerianos: Nivel 4 (Vordergrund) = superficie: todos los acordes compás a compás. Nivel 3 (Mittelgrund cercano): funciones armónicas principales. Nivel 2 (Mittelgrund profundo): regiones tonales y prolongaciones. Nivel 1 (Hintergrund): Urlinie + Bassbrechung solamente. Cada reducción revela una capa de significado estructural." },
  { q: "¿Qué es el 'Vordergrund' en el análisis schenkeriano?", opts: ["La estructura más profunda", "El primer plano — la superficie musical con todos sus detalles: melodía, acordes, ornamentos, ritmo", "La parte de piano del primer plano", "El motivo principal"], a: 0, fb: "Vordergrund = 'primer plano' = la superficie musical completa tal como se interpreta. Todo lo que se escucha: ornamentos, notas de paso, arpegios, bordaduras, retardos, apoyaturas. Es el punto de partida del análisis — se reduce luego para descubrir los niveles más profundos." },
  { q: "¿Qué es el 'Hintergrund' en el análisis schenkeriano?", opts: ["El fondo orquestal", "El fondo estructural — el nivel más profundo: Urlinie + Bassbrechung. El esqueleto armónico bajo todo el ornamento de superficie", "La parte del bajo únicamente", "La forma global (sonata, rondó)"], a: 1, fb: "Hintergrund = 'fondo' = la estructura fundamental. Es el Ursatz: la línea melódica descendente (Urlinie, desde el 5.º, 3.er u 8.º grado hasta la tónica) sostenida por el bajo arpegiado I–V–I. Este nivel revela cómo toda la complejidad de superficie es una ornamentación de una estructura armónica simple." },
  { q: "¿Cuál es el significado del símbolo 5̂ (sombrero sobre el número 5) en la notación schenkeriana?", opts: ["El 5.º acorde del ciclo de quintas", "El 5.º grado de la escala como nota de la Urlinie — punto de partida frecuente de la línea estructural descendente", "El 5.º compás de la obra", "El acorde de dominante"], a: 1, fb: "La notación ̂ (acento circunflejo) indica un grado escalar estructural de la Urlinie. 5̂ = el 5.º grado de la escala como nota de inicio de la línea fundamental. La Urlinie comienza típicamente en 5̂, 3̂ o 8̂ y desciende por grados conjuntos hasta 1̂ (la tónica). 5̂–4̂–3̂–2̂–1̂ es la Urlinie de 5 notas más completa." },
  { q: "¿Qué es una 'nota de bordadura' (Nebennote) en el análisis schenkeriano?", opts: ["Una nota añadida para la virtuosidad pianística", "Un ornamento que se aleja de una nota estructural un grado hacia arriba o hacia abajo, y luego regresa — la nota estructural 'rodea' el ornamento", "Una nota perteneciente al contrasujeto de una fuga", "Una nota cromática"], a: 1, fb: "La nota de bordadura (Nebennote) es una ornamentación: la nota estructural parte hacia el grado adyacente (superior o inferior) y regresa. Do–Re–Do: el Re es una bordadura superior del Do estructural. En la reducción schenkeriana, las bordaduras desaparecen en los niveles más profundos para revelar la nota estructural." },
  { q: "¿Qué es una 'nota de paso' (Durchgangsnote) en el análisis schenkeriano?", opts: ["Una nota que modifica el tempo", "Una nota que rellena el espacio entre dos notas estructurales, generalmente por movimiento conjunto", "Una nota tocada fortissimo", "Una nota del contrasujeto"], a: 1, fb: "La nota de paso (Durchgangsnote) conecta dos notas estructurales por movimiento conjunto: Do–Re–Mi, si Do y Mi son estructurales, Re es una nota de paso. En la reducción, las notas de paso desaparecen para revelar la conexión directa entre las notas estructurales. Crean el movimiento melódico de superficie." },
  { q: "¿Era Heinrich Schenker un compositor o un teórico?", opts: ["Únicamente compositor (ninguna teoría)", "Principalmente teórico y crítico musical — compuso poco pero desarrolló la mayor teoría analítica del siglo XX", "Un intérprete virtuoso de piano sin teoría", "Un alumno de Brahms que no publicó ningún texto"], a: 1, fb: "Heinrich Schenker (1868–1935) fue teórico, crítico musical y profesor vienés. Estudió con Brahms y desarrolló su teoría analítica en varias obras monumentales: Harmonielehre (1906), Counterpoint (1910–1922) y Der freie Satz (1935, póstumo). Su método analítico se enseña en universidades de todo el mundo." },
  { q: "¿Por qué el análisis schenkeriano es a veces criticado?", opts: ["Porque es demasiado simple", "Porque se aplica con dificultad a la música no tonal (atonal, modal) y porque sus 'leyes' a veces reflejan el gusto personal de Schenker más que una verdad universal", "Porque solo sirve para Bach", "Porque es demasiado cuantitativo y matemático"], a: 1, fb: "El análisis schenkeriano tiene límites: 1/ Solo se aplica a la música tonal (no atonal ni modal). 2/ Las decisiones de reducción son a veces subjetivas. 3/ El propio Schenker tenía gustos estéticos marcados (adoraba a Brahms, detestaba a Debussy) que influían en sus análisis. Estas críticas no restan poder a la herramienta para la música tonal." },
  { q: "¿Cuál es la fórmula de Urlinie más frecuente en las piezas tonales cortas?", opts: ["8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (octava completa)", "3̂–2̂–1̂ (línea descendente desde la tercera hasta la tónica)", "5̂–4̂–3̂ (descenso parcial)", "1̂–2̂–1̂ (bordadura de tónica)"], a: 1, fb: "La Urlinie 3̂–2̂–1̂ es la más frecuente en piezas cortas y sencillas: la melodía estructural desciende desde el 3.er grado (mediante) hasta la tónica pasando por la supratónica. Es la Urlinie de muchos preludios de Bach, melodías folclóricas y piezas clásicas cortas. La Urlinie 5̂–1̂ es más amplia, típica de sonatas y sinfonías." },
  { q: "¿Qué es el 'Kopfton' en el análisis schenkeriano?", opts: ["La nota más aguda de la obra", "La nota de inicio de la Urlinie — el punto desde el cual la línea melódica estructural desciende hasta la tónica", "El primer acorde de la exposición", "La nota pivote de una modulación"], a: 1, fb: "Kopfton = 'nota cabeza'. Es la nota de inicio de la Urlinie, generalmente 3̂, 5̂ o 8̂. Toda la música puede verse como la elaboración del recorrido entre el Kopfton y la tónica final (1̂). Identificar el Kopfton es un paso clave del análisis — determina qué versión de la Urlinie está en juego y cómo la melodía de superficie 'desciende' estructuralmente." },
  { q: "¿Cómo ayuda la reducción schenkeriana a comprender una modulación?", opts: ["Muestra que todas las modulaciones son falsas", "Revela si la modulación es estructural (cambia el nivel 2) o de superficie (ornamental, cambio temporal que regresa al nivel 1 idéntico)", "Elimina las modulaciones del análisis", "Transforma todas las modulaciones en préstamos modales"], a: 1, fb: "La reducción schenkeriana distingue la modulación estructural (el nivel 2 cambia de región tonal — el Mittelgrund se modifica) de la modulación de superficie (ornamental — el nivel 1 regresa al mismo Hintergrund). Muchas modulaciones aparentes en Beethoven o Mozart son en realidad prolongaciones ornamentales que regresan a la tonalidad inicial sin cambiar la estructura profunda." },
  { q: "¿Cuál es el motivo básico de la 5.ª Sinfonía de Beethoven op. 67?", opts: ["Do–Re–Mi–Fa (escala ascendente de 4 notas)", "Sol–Sol–Sol–Mib (3 corcheas + negra: ritmo corto-corto-corto-largo)", "Fa–Mi–Re–Do (escala descendente)", "La–Sol–Fa–Mi (tetracordio descendente)"], a: 1, fb: "El motivo inicial de la 5.ª Sinfonía es Sol–Sol–Sol–Mib — 3 corcheas + 1 negra (el ritmo «ta-ta-ta-TUM»). Este motivo de 4 notas no es solo un tema introductorio: es el material generador de toda la obra. Beethoven lo transforma, lo aumenta, lo invierte y lo fragmenta a lo largo de los 4 movimientos. Es el motivo más célebre de toda la literatura musical." },
  { q: "¿Cómo se transforma el motivo Sol–Sol–Sol–Mib en el 2.º movimiento de la 5.ª Sinfonía?", opts: ["Desaparece completamente", "Se transforma en modo mayor con un contorno melódico diferente pero conservando el ritmo corto-corto-corto-largo", "Se toca idéntico pero transportado", "Se invierte melódicamente"], a: 1, fb: "En el 2.º movimiento (Andante con moto), el motivo rítmico corto-corto-corto-largo se conserva pero se integra en una melodía lírica mayor muy diferente de la brutalidad del 1.er movimiento. El contorno melódico cambia, pero la identidad rítmica permite reconocer el motivo transformado. Beethoven muestra que el motivo trasciende sus cualidades superficiales." },
  { q: "¿Qué es la 'fragmentación' de un motivo?", opts: ["Suprimir el motivo completamente", "Reducir el motivo a uno de sus elementos constitutivos — tocar solo el ritmo, o solo las 2 primeras notas, para crear tensión o expectación", "Tocar el motivo en aumentación", "Combinar dos motivos diferentes"], a: 1, fb: "La fragmentación descompone el motivo en sus elementos. En el desarrollo del 1.er movimiento de la 5.ª Sinfonía, Beethoven fragmenta el motivo a una sola cuarta (Sol–Mib), luego a una sola negra (solo el ritmo, sin melodía). Esta reducción progresiva crea una tensión extrema — el motivo es 'desgarrado' antes de ser reensamblado en la reexposición." },
  { q: "¿Qué es la 'secuencia' motívica como técnica de desarrollo?", opts: ["Repetir el motivo en la misma altura", "Repetir el motivo transportándolo a intervalos regulares — el mismo contorno melódico y rítmico sube o baja por grados", "Invertir el motivo melódicamente", "Aumentar la duración de todas las notas"], a: 1, fb: "La secuencia es la repetición de un motivo transportado a intervalos regulares. Motivo en Do, luego en Si, luego en La (secuencia descendente por grados). La secuencia crea un fuerte movimiento direccional — 'arrastra' la música hacia un objetivo. Bach, Handel, Vivaldi y Beethoven la usan masivamente en las transiciones y los desarrollos." },
  { q: "¿Cuál es el 'motivo generador' en los Cuartetos de cuerda de Brahms op. 51?", opts: ["Una tercera mayor ascendente", "Un intervalo de segunda (a menudo menor) que se encuentra en todas las formas (ascendente, descendente, aumentado, invertido) a lo largo de toda la obra", "Un ritmo de tres corcheas", "Un acorde de séptima disminuida"], a: 1, fb: "En el op. 51 de Brahms, un intervalo de segunda estructura cada movimiento. El análisis revela que el mismo intervalo (Sol–Lab, por ejemplo) reaparece en todas partes: en el tema principal, el contrasujeto, la melodía del 2.º movimiento, el scherzo. Es la 'economía motívica' de Brahms — componer el máximo con el mínimo de material." },
  { q: "¿Cómo transforma Beethoven el motivo de la 5.ª Sinfonía en el 4.º movimiento final?", opts: ["Lo suprime para terminar con un tema nuevo", "Lo presenta triunfalmente en mayor, aumentado y glorificado — la 'victoria' de la tonalidad menor hacia la mayor", "Lo toca exactamente como al principio", "Lo invierte melódicamente"], a: 1, fb: "El 4.º movimiento (Allegro, Do mayor) es la 'respuesta' al 1.º (Do menor). El motivo Sol–Sol–Sol–Mib, primero oscuro y amenazante, se vuelve triunfante en mayor con los metales a plena potencia. La transformación modal (menor → mayor) y dinámica (forte dramático → fortissimo victorioso) significa la resolución del conflicto de toda la sinfonía." },
  { q: "¿Qué es el análisis de 'conducción de voces' en un contexto analítico (no compositivo)?", opts: ["Identificar las voces de una fuga", "Trazar cómo cada voz de un acorde se desplaza hacia las notas del acorde siguiente — identificar movimientos conjuntos, saltos, notas tenidas y notas comunes", "Analizar la tesitura de los cantantes", "Contar el número de voces en una fuga"], a: 1, fb: "El análisis de conducción de voces sigue cada línea individual en una progresión armónica. En un I–IV–V–I, ¿cómo se mueve el soprano? ¿El contralto? ¿El bajo? Se trazan las notas comunes (ligadas), los movimientos conjuntos (fluidos) y los saltos. Este análisis revela la lógica lineal subyacente a la progresión armónica." },
  { q: "¿Cuál es el método de 4 pasos para realizar un análisis schenkeriano de una pieza?", opts: ["1-Escuchar 2-Tocar 3-Memorizar 4-Interpretar", "1-Identificar las cadencias estructurales 2-Trazar el bajo estructural 3-Identificar las notas melódicas estructurales 4-Reducir progresivamente hasta el Ursatz", "1-Analizar los acordes 2-Nombrar las funciones 3-Identificar la tonalidad 4-Escribir el resumen", "1-Identificar el sujeto 2-La respuesta 3-El contrasujeto 4-Los episodios"], a: 1, fb: "El método analítico schenkeriano: 1/ Identificar las cadencias estructurales (V→I auténticas) que delimitan las secciones; 2/ Trazar la línea de bajo estructural (fundamentales de las armonías importantes); 3/ Identificar las notas melódicas estructurales (notas sostenidas largas, notas cadenciales); 4/ Reducir progresivamente hasta el Ursatz simple." },
  { q: "¿Cómo distingue la notación schenkeriana las notas estructurales de las ornamentales?", opts: ["Por el color de las notas (negras vs blancas)", "Por el uso de cabezas de nota con plicas (notas estructurales) frente a sin plicas (ornamentales), más ligaduras para las prolongaciones", "Por la posición en el pentagrama (graves vs agudas)", "Por la cifra romana (I, V) vs arábiga (1, 2)"], a: 1, fb: "La notación schenkeriana utiliza un sistema gráfico específico: notas estructurales = cabezas de nota con plicas; notas ornamentales = sin plica o en tamaño pequeño; ligaduras curvas = prolongaciones armónicas; ligaduras melódicas = conexiones entre notas estructurales. El sistema visual revela la jerarquía analítica de un vistazo." },
  { q: "¿Por qué el análisis motívico de la 5.ª Sinfonía es más informativo que el análisis acorde por acorde?", opts: ["El análisis de acordes es más rápido de realizar", "El análisis motívico revela la coherencia arquitectónica a lo largo de 4 movimientos — cómo un solo motivo de 4 notas estructura 35 minutos de música, algo que un análisis compás a compás no puede mostrar", "El análisis motívico es menos preciso pero más artístico", "Ambos análisis proporcionan exactamente la misma información"], a: 1, fb: "El análisis acorde por acorde describe la superficie armónica de cada compás pero no revela cómo están conectados esos compases. El análisis motívico muestra la coherencia: el motivo Sol–Sol–Sol–Mib regresa en 15 formas diferentes en 35 minutos. Esta unidad estructural profunda es lo que hace de la 5.ª Sinfonía una obra unificada y no una colección de temas." },
  { q: "¿Qué es la 'disminución' de un motivo como técnica de desarrollo?", opts: ["Tocar el motivo más suavemente (diminuendo)", "Tocar el motivo en valores rítmicos reducidos — cada negra se convierte en corchea, cada corchea en semicorchea", "Reducir el número de notas del motivo", "Transportar el motivo más abajo"], a: 1, fb: "La disminución es lo opuesto de la aumentación: el motivo se toca en valores rítmicos reducidos. Un motivo de negras se convierte en corcheas, las corcheas en semicorcheas. El efecto es acelerar y aligerar el motivo — crear agitación o brillantez donde la aumentación crea gravedad. Técnica usada en los desarrollos para acelerar progresivamente." },
  { q: "¿Qué aporta el análisis motívico respecto al análisis formal (sonata, rondó)?", opts: ["El análisis formal es más completo — reemplaza el análisis motívico", "El análisis formal describe la estructura externa (A-B-A, exposición-desarrollo-reexposición); el análisis motívico revela la sustancia interna (cómo un motivo genera el contenido de cada sección)", "Son idénticos e intercambiables", "El análisis motívico solo se aplica a piezas modernas"], a: 1, fb: "El análisis formal identifica las 'casillas' de la forma: exposición, desarrollo, reexposición, coda. El análisis motívico llena esas casillas de significado: qué se desarrolla en el desarrollo (qué motivos, qué transformaciones), por qué la reexposición difiere de la exposición (qué motivos han evolucionado). Los dos análisis son complementarios — ninguno es suficiente por sí solo." },
];

const questionsDe: Question[] = [
  { q: "Was ist der Ursatz nach Heinrich Schenker?", opts: ["Ein 4-nötiges Fugenthema", "Die fundamentale Harmoniestruktur aller tonalen Musik: Urlinie (absteigende Melodielinie 5̂–1̂) + Bassbrechung (Bassarpeggierung I–V–I)", "Der Tonikadreiklang in einer Kadenz", "Das erste Thema einer Sonatenform"], a: 1, fb: "Der Ursatz ('Grundstruktur') ist das harmonische Gerüst aller tonalen Musik nach Schenker. Er umfasst die Urlinie (absteigende Melodielinie vom 5., 3. oder 8. Skalenstufe zur Tonika) und die Bassbrechung (Bass, der I–V–I arpeggiert). Alles andere in der Musik ist 'Prolongation' oder 'Ornament' dieses zugrundeliegenden Ursatzes." },
  { q: "Was ist 'harmonische Prolongation' in der Schenker-Analyse?", opts: ["Die Verlängerung der Dauer eines Akkords", "Die Ausarbeitung einer Strukturharmonie durch Zwischenharmonien — die Tonika 'hält' harmonisch an, auch wenn nicht-tonische Akkorde sie vorübergehend schmücken", "Ein Bassliegeton", "Ein Tremolo auf einem Akkord"], a: 1, fb: "Prolongation bedeutet, dass eine Strukturharmonie (meist I oder V) ihren Einfluss ausübt, während Durchgangsharmonien oder Verzierungen sie an der Oberfläche ornamentieren. In 32 scheinbar abwechslungsreichen Takten kann die Analyse zeigen, dass die Tonika 'prolongiert' wird — Oberflächenänderungen verändern die Tiefenstruktur nicht." },
  { q: "Was sind die 4 Reduktionsebenen in der Schenker-Analyse?", opts: ["Ebene A (Dur), B (Moll), C (chromatisch), D (diatonisch)", "Ebene 4 (Oberfläche, alle Akkorde), 3 (Mittelgrund nah), 2 (Tonalregionen), 1 (Urlinie/Struktur)", "Ebene 1 (Noten), 2 (Takte), 3 (Phrasen), 4 (Abschnitte)", "Ebenen I, V, II, IV nach harmonischen Funktionen"], a: 1, fb: "Die 4 Schenker-Ebenen: Ebene 4 (Vordergrund) = Oberfläche: alle Akkorde Takt für Takt. Ebene 3 (naher Mittelgrund): wichtigste Harmonikfunktionen. Ebene 2 (tiefer Mittelgrund): Tonalregionen und Prolongationen. Ebene 1 (Hintergrund): nur Urlinie + Bassbrechung. Jede Reduktion enthüllt eine Schicht strukturellen Sinns." },
  { q: "Was ist der 'Vordergrund' in der Schenker-Analyse?", opts: ["Die tiefste Struktur", "Der Vordergrund — die musikalische Oberfläche mit allen Details: Melodie, Akkorde, Ornamente, Rhythmus", "Die Klavierstimme im Vordergrund", "Das Hauptmotiv"], a: 0, fb: "Vordergrund = 'Vordergrund' = die vollständige musikalische Oberfläche, wie sie gespielt wird. Alles, was man hört: Ornamente, Durchgangsnoten, Arpeggios, Nebennoten, Vorhalte, Appoggiaturen. Dies ist der Ausgangspunkt der Analyse — dann wird reduziert, um tiefere Ebenen zu entdecken." },
  { q: "Was ist der 'Hintergrund' in der Schenker-Analyse?", opts: ["Der orchestrale Hintergrund", "Der strukturelle Hintergrund — die tiefste Ebene: Urlinie + Bassbrechung. Das harmonische Gerüst unter aller Oberflächenornamentik", "Nur die Bassstimme", "Die Gesamtform (Sonate, Rondo)"], a: 1, fb: "Hintergrund = 'Hintergrund' = die fundamentale Struktur. Das ist der Ursatz: die absteigende Melodielinie (Urlinie, vom 5., 3. oder 8. Grad zur Tonika) gestützt durch den arpeggierenden Bass I–V–I. Diese Ebene zeigt, wie alle Oberflächenkomplexität eine Ornamentierung einer einfachen Harmoniestruktur ist." },
  { q: "Was bedeutet das Symbol 5̂ (Dach über der Zahl 5) in der Schenker-Notation?", opts: ["Der 5. Akkord im Quintenzirkel", "Die 5. Skalenstufe als Urlinie-Note — häufiger Ausgangspunkt der absteigenden Strukturlinie", "Der 5. Takt des Werkes", "Der Dominantakkord"], a: 1, fb: "Die ̂-Notation (Zirkumflex) bezeichnet eine strukturelle Skalenstufe der Urlinie. 5̂ = die 5. Skalenstufe als Anfangsnote der Grundlinie. Die Urlinie beginnt typischerweise auf 5̂, 3̂ oder 8̂ und steigt stufenweise bis 1̂ (Tonika) ab. 5̂–4̂–3̂–2̂–1̂ ist die vollständigste 5-notige Urlinie." },
  { q: "Was ist eine 'Nebennote' in der Schenker-Analyse?", opts: ["Eine Note für pianistische Virtuosität", "Eine Verzierung, die sich von einer Strukturnote um einen Grad nach oben oder unten entfernt und zurückkehrt — die Strukturnote 'umrahmt' das Ornament", "Eine Note des Kontrasujets einer Fuge", "Eine chromatische Note"], a: 1, fb: "Die Nebennote ist eine Ornamentierung: die Strukturnote bewegt sich zum benachbarten Grad (oben oder unten) und kehrt zurück. C–D–C: das D ist eine obere Nebennote des strukturellen C. In der Schenker-Reduktion verschwinden Nebennoten auf tieferen Ebenen, um die Strukturnote zu enthüllen." },
  { q: "Was ist eine 'Durchgangsnote' in der Schenker-Analyse?", opts: ["Eine Note, die das Tempo ändert", "Eine Note, die den Raum zwischen zwei Strukturnoten füllt, meist durch Stufenbewegung", "Eine fortissimo gespielte Note", "Eine Note des Kontrasujets"], a: 1, fb: "Die Durchgangsnote verbindet zwei Strukturnoten durch Stufenbewegung: C–D–E, wenn C und E Strukturnoten sind, ist D eine Durchgangsnote. In der Reduktion verschwinden Durchgangsnoten, um die direkte Verbindung zwischen Strukturnoten zu enthüllen. Sie schaffen die melodische Oberflächenbewegung." },
  { q: "War Heinrich Schenker Komponist oder Theoretiker?", opts: ["Nur Komponist (keine Theorie)", "Hauptsächlich Musiktheoretiker und -kritiker — er komponierte wenig, entwickelte aber die bedeutendste Analysetheorie des 20. Jahrhunderts", "Ein virtuoser Klavierinterpreter ohne Theorie", "Ein Schüler von Brahms, der keine Texte veröffentlichte"], a: 1, fb: "Heinrich Schenker (1868–1935) war Wiener Theoretiker, Musikkritiker und Lehrer. Er studierte bei Brahms und entwickelte seine Analysetheorie in mehreren monumentalen Werken: Harmonielehre (1906), Kontrapunkt (1910–1922) und Der freie Satz (1935, postum). Seine Analysemethode wird weltweit an Universitäten gelehrt." },
  { q: "Warum wird die Schenker-Analyse manchmal kritisiert?", opts: ["Weil sie zu einfach ist", "Weil sie sich schwer auf nicht-tonale Musik (atonal, modal) anwenden lässt und weil ihre 'Gesetze' manchmal Schenkers persönlichen Geschmack mehr als eine universelle Wahrheit widerspiegeln", "Weil sie nur für Bach geeignet ist", "Weil sie zu quantitativ und mathematisch ist"], a: 1, fb: "Die Schenker-Analyse hat Grenzen: 1/ Sie gilt nur für tonale Musik (nicht atonal oder modal). 2/ Reduktionsentscheidungen sind manchmal subjektiv. 3/ Schenker selbst hatte ausgeprägte ästhetische Vorlieben (liebte Brahms, mochte Debussy nicht), die seine Analysen beeinflussten. Diese Kritiken schmälern die Stärke des Werkzeugs für tonale Musik nicht." },
  { q: "Was ist die häufigste Urlinie-Formel in kurzen Tonalstücken?", opts: ["8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (vollständige Oktave)", "3̂–2̂–1̂ (absteigende Linie von der Terz zur Tonika)", "5̂–4̂–3̂ (Teilabstieg)", "1̂–2̂–1̂ (Tonika-Nebennote)"], a: 1, fb: "Die Urlinie 3̂–2̂–1̂ ist die häufigste in kurzen, einfachen Stücken: die Strukturmelodie steigt vom 3. Grad (Mediante) über die Supratonika zur Tonika ab. Das ist die Urlinie vieler Bach-Präludien, Volksmelodien und kurzer klassischer Stücke. Die Urlinie 5̂–1̂ ist breiter, typisch für Sonaten und Sinfonien." },
  { q: "Was ist der 'Kopfton' in der Schenker-Analyse?", opts: ["Die höchste Note des Werkes", "Die Anfangsnote der Urlinie — der Punkt, von dem die Strukturmelodielinie zur Tonika absteigt", "Der erste Akkord der Exposition", "Die Drehnote einer Modulation"], a: 1, fb: "Kopfton = 'Kopfnote'. Es ist die Anfangsnote der Urlinie, meist 3̂, 5̂ oder 8̂. Die gesamte Musik kann als Ausarbeitung des Weges zwischen dem Kopfton und der Schlusstonika (1̂) gesehen werden. Den Kopfton zu identifizieren ist ein Schlüsselschritt der Analyse — er bestimmt, welche Version der Urlinie vorliegt." },
  { q: "Wie hilft die Schenker-Reduktion, eine Modulation zu verstehen?", opts: ["Sie zeigt, dass alle Modulationen falsch sind", "Sie enthüllt, ob die Modulation strukturell ist (ändert Ebene 2) oder oberflächlich (ornamental, vorübergehende Änderung, die zur gleichen Ebene 1 zurückkehrt)", "Sie entfernt Modulationen aus der Analyse", "Sie verwandelt alle Modulationen in modale Entlehnungen"], a: 1, fb: "Die Schenker-Reduktion unterscheidet strukturelle Modulation (Ebene 2 wechselt Tonalregion — der Mittelgrund verändert sich) von Oberflächenmodulation (ornamental — Ebene 1 kehrt zum gleichen Hintergrund zurück). Viele scheinbare Modulationen bei Beethoven oder Mozart sind tatsächlich ornamentale Prolongationen, die ohne Veränderung der Tiefenstruktur zur Ausgangstonart zurückkehren." },
  { q: "Was ist das Grundmotiv der 5. Sinfonie von Beethoven op. 67?", opts: ["C–D–E–F (aufsteigende 4-Noten-Skala)", "G–G–G–Es (3 Achtelnoten + Viertelnote: kurz-kurz-kurz-lang-Rhythmus)", "F–E–D–C (absteigende Skala)", "A–G–F–E (absteigendes Tetrachord)"], a: 1, fb: "Das Eingangsmotiv der 5. Sinfonie ist G–G–G–Es — 3 Achtelnoten + 1 Viertelnote (der 'ta-ta-ta-TUM'-Rhythmus). Dieses 4-Noten-Motiv ist nicht nur ein Einführungsthema: es ist das Generativmaterial des gesamten Werkes. Beethoven transformiert, augmentiert, invertiert und fragmentiert es über alle 4 Sätze hinweg. Es ist das berühmteste Motiv der gesamten Musikliteratur." },
  { q: "Wie wird das G–G–G–Es-Motiv im 2. Satz der 5. Sinfonie transformiert?", opts: ["Es verschwindet vollständig", "Es wird in Durtonart mit anderem melodischen Kontur transformiert, aber der kurz-kurz-kurz-lang-Rhythmus bleibt erhalten", "Es wird identisch gespielt, aber transponiert", "Es wird melodisch umgekehrt"], a: 1, fb: "Im 2. Satz (Andante con moto) bleibt das rhythmische kurz-kurz-kurz-lang-Motiv erhalten, aber in eine lyrische Durmelodie integriert, sehr verschieden von der Brutalität des 1. Satzes. Der melodische Kontur ändert sich, aber die rhythmische Identität ermöglicht es, das transformierte Motiv zu erkennen. Beethoven zeigt, dass das Motiv seine Oberflächenqualitäten transzendiert." },
  { q: "Was ist die 'Fragmentierung' eines Motivs?", opts: ["Das Motiv vollständig zu streichen", "Das Motiv auf eines seiner Bestandteile zu reduzieren — nur den Rhythmus oder nur die ersten 2 Noten spielen, um Spannung oder Erwartung zu erzeugen", "Das Motiv in Augmentation zu spielen", "Zwei verschiedene Motive zu kombinieren"], a: 1, fb: "Fragmentierung zerlegt das Motiv in seine Elemente. In der 5. Sinfonie, Durchführung des 1. Satzes, fragmentiert Beethoven das Motiv zu einer einzigen Quarte (G–Es), dann zu einer einzigen Viertelnote (nur Rhythmus, keine Melodie). Diese schrittweise Reduktion erzeugt extreme Spannung — das Motiv wird 'zerrissen', bevor es in der Reprise wieder zusammengesetzt wird." },
  { q: "Was ist eine motivische 'Sequenz' als Entwicklungstechnik?", opts: ["Das Motiv auf derselben Tonhöhe zu wiederholen", "Das Motiv in regelmäßigen Abständen zu transponieren — derselbe melodische und rhythmische Kontur steigt stufenweise auf oder ab", "Das Motiv melodisch umzukehren", "Die Dauer aller Noten zu verlängern"], a: 1, fb: "Eine Sequenz ist die Wiederholung eines Motivs in regelmäßigen Transpositionsabständen. Motiv auf C, dann auf H, dann auf A (absteigende Stufensequenz). Die Sequenz erzeugt starke gerichtete Bewegung — sie 'zieht' die Musik auf ein Ziel hin. Bach, Händel, Vivaldi und Beethoven verwenden sie massiv für Übergänge und Durchführungen." },
  { q: "Was ist das 'Generativmotiv' in Brahms' Streichquartetten op. 51?", opts: ["Eine aufsteigende große Terz", "Ein Sekundintervall (oft klein), das in allen Formen (aufsteigend, absteigend, augmentiert, invertiert) im gesamten Werk auftaucht", "Ein Drei-Achtel-Rhythmus", "Ein verminderter Septakkord"], a: 1, fb: "In Brahms' op. 51 strukturiert ein Sekundintervall jeden Satz. Die Analyse zeigt, dass dasselbe Intervall (z. B. G–As) überall auftaucht: im Hauptthema, im Kontrathema, der Melodie des 2. Satzes, dem Scherzo. Das ist Brahms' 'Motivökonomie' — mit minimalem Material maximalen Output zu komponieren." },
  { q: "Wie transformiert Beethoven das Motiv der 5. Sinfonie im 4. Schlusssatz?", opts: ["Er entfernt es, um mit einem neuen Thema zu enden", "Er präsentiert es triumphierend in Dur, augmentiert und verherrlicht — der 'Sieg' von Moll nach Dur", "Er spielt es genau wie zu Beginn", "Er kehrt es melodisch um"], a: 1, fb: "Der 4. Satz (Allegro, C-Dur) ist die 'Antwort' auf den 1. (c-Moll). Das Motiv G–G–G–Es, zunächst düster und bedrohlich, wird triumphierend in Dur mit Blechbläsern voller Kraft. Die modale Transformation (Moll → Dur) und dynamische Verschiebung (dramatisches Forte → siegreiches Fortissimo) bedeutet die Auflösung des Konflikts der gesamten Sinfonie." },
  { q: "Was ist die 'Stimmführungsanalyse' in einem analytischen (nicht kompositorischen) Kontext?", opts: ["Die Stimmen einer Fuge identifizieren", "Nachverfolgen, wie sich jede Stimme eines Akkords zu den Noten des nächsten Akkords bewegt — Stufenbewegung, Sprünge, gehaltene Noten und gemeinsame Töne identifizieren", "Die Tessitura von Sängern analysieren", "Die Anzahl der Stimmen in einer Fuge zählen"], a: 1, fb: "Die Stimmführungsanalyse verfolgt jede einzelne Linie in einer Harmoniefolge. In einem I–IV–V–I: wie bewegt sich der Sopran? Der Alt? Der Bass? Man verfolgt gemeinsame Töne (gebunden), Stufenbewegungen (fließend) und Sprünge. Diese Analyse enthüllt die lineare Logik unter der Harmoniefolge." },
  { q: "Was ist die 4-Schritte-Methode für eine Schenker-Analyse eines Stücks?", opts: ["1-Hören 2-Spielen 3-Auswendiglernen 4-Interpretieren", "1-Strukturkadenzen identifizieren 2-Strukturbass nachzeichnen 3-Strukturmelodienoten identifizieren 4-Progressiv bis zum Ursatz reduzieren", "1-Akkorde analysieren 2-Funktionen benennen 3-Tonart identifizieren 4-Zusammenfassung schreiben", "1-Thema identifizieren 2-Antwort 3-Kontrathema 4-Episoden"], a: 1, fb: "Die Schenker-Analysemethode: 1/ Strukturkadenzen (authentische V→I) identifizieren, die Abschnitte abgrenzen; 2/ Strukturbasslinie nachzeichnen (Grundtöne wichtiger Harmonien); 3/ Strukturmelodienoten identifizieren (lang gehaltene Noten, Kadenznoten); 4/ Progressiv bis zum einfachen Ursatz reduzieren." },
  { q: "Wie unterscheidet die Schenker-Notation Strukturnoten von Ornamentnoten?", opts: ["Durch die Notenfarbe (schwarz vs weiß)", "Durch die Verwendung von Notenköpfen mit Hälsen (Strukturnoten) vs ohne Hälse (ornamentale), plus Legatobögen für Prolongationen", "Durch die Position im Notensystem (tief vs hoch)", "Durch römische (I, V) vs arabische (1, 2) Bezifferung"], a: 1, fb: "Die Schenker-Notation verwendet ein spezifisches grafisches System: Strukturnoten = Notenköpfe mit Hälsen; Ornamentnoten = ohne Hälse oder in kleiner Größe; Legatobögen = harmonische Prolongationen; melodische Bögen = Verbindungen zwischen Strukturnoten. Das visuelle System enthüllt die analytische Hierarchie auf einen Blick." },
  { q: "Warum ist die Motivanalyse der 5. Sinfonie informativer als die Akkord-für-Akkord-Analyse?", opts: ["Die Akkordanalyse ist schneller durchzuführen", "Die Motivanalyse enthüllt die architektonische Kohärenz über 4 Sätze — wie ein einziges 4-Noten-Motiv 35 Minuten Musik strukturiert, was eine taktweise Akkordanalyse nicht zeigen kann", "Die Motivanalyse ist weniger präzise, aber künstlerischer", "Beide Analysen liefern genau dieselben Informationen"], a: 1, fb: "Die Akkord-für-Akkord-Analyse beschreibt die Harmonieoberfläche jedes Taktes, zeigt aber nicht, wie diese Takte verbunden sind. Die Motivanalyse zeigt die Kohärenz: das G–G–G–Es-Motiv kehrt in 15 verschiedenen Formen in 35 Minuten zurück. Diese tiefe strukturelle Einheit ist es, die die 5. Sinfonie zu einem einheitlichen Werk und nicht zu einer Themensammlung macht." },
  { q: "Was ist die 'Diminution' eines Motivs als Entwicklungstechnik?", opts: ["Das Motiv leiser spielen (diminuendo)", "Das Motiv in verkürzten Rhythmuswerten spielen — jede Viertelnote wird zur Achtelnote, jede Achtelnote zur Sechzehntelnote", "Die Anzahl der Noten im Motiv reduzieren", "Das Motiv tiefer transponieren"], a: 1, fb: "Diminution ist das Gegenteil von Augmentation: das Motiv wird in verkürzten Rhythmuswerten gespielt. Ein Motiv aus Viertelnoten wird zu Achtelnoten, Achtelnoten zu Sechzehntelnoten. Der Effekt ist, das Motiv zu beschleunigen und aufzuhellen — Aufregung oder Brillanz zu schaffen, wo Augmentation Schwere schafft. In Durchführungen verwendet, um progressiv zu beschleunigen." },
  { q: "Was trägt die Motivanalyse im Vergleich zur Formanalyse (Sonate, Rondo) bei?", opts: ["Formanalyse ist vollständiger — sie ersetzt die Motivanalyse", "Formanalyse beschreibt die äußere Struktur (A-B-A, Exposition-Durchführung-Reprise); Motivanalyse enthüllt die innere Substanz (wie ein Motiv den Inhalt jedes Abschnitts erzeugt)", "Sie sind identisch und austauschbar", "Motivanalyse gilt nur für moderne Stücke"], a: 1, fb: "Formanalyse identifiziert die 'Kästchen' der Form: Exposition, Durchführung, Reprise, Coda. Motivanalyse füllt diese Kästchen mit Bedeutung: was in der Durchführung entwickelt wird (welche Motive, welche Transformationen), warum die Reprise sich von der Exposition unterscheidet (welche Motive sich entwickelt haben). Beide Analysen ergänzen sich — keine ist für sich allein ausreichend." },
];

const questionsIt: Question[] = [
  { q: "Che cos'è l'Ursatz secondo Heinrich Schenker?", opts: ["Un motivo di 4 note in una fuga", "La struttura armonica fondamentale di tutta la musica tonale: Urlinie (linea melodica discendente 5̂–1̂) + Bassbrechung (arpeggio del basso I–V–I)", "L'accordo di tonica in una cadenza", "Il primo tema di una forma sonata"], a: 1, fb: "L'Ursatz ('struttura fondamentale') è l'ossatura armonica di tutta la musica tonale secondo Schenker. Comprende la Urlinie (linea melodica discendente dal 5°, 3° o 8° grado scalare fino alla tonica) e la Bassbrechung (basso che arpeggia I–V–I). Tutto il resto nella musica è 'prolungazione' o 'ornamento' di questo Ursatz sottostante." },
  { q: "Che cos'è la 'prolungazione armonica' nell'analisi schenkeriana?", opts: ["Allungare la durata di un accordo", "L'elaborazione di un'armonia strutturale mediante armonie intermedie — la tonica 'persiste' armonicamente anche quando accordi non-tonici la decorano temporaneamente", "Un pedale di basso", "Un tremolo su un accordo"], a: 1, fb: "La prolungazione significa che un'armonia strutturale (di solito I o V) continua a esercitare la sua influenza mentre armonie di passaggio o abbellimenti la ornamentano in superficie. In 32 misure apparentemente variegate, l'analisi può mostrare che la tonica è 'prolungata' — i cambiamenti superficiali non alterano la struttura profonda." },
  { q: "Quali sono i 4 livelli di riduzione nell'analisi schenkeriana?", opts: ["Livello A (maggiore), B (minore), C (cromatico), D (diatonico)", "Livello 4 (superficie, tutti gli accordi), 3 (intermedio), 2 (regioni tonali), 1 (Urlinie/struttura)", "Livello 1 (note), 2 (misure), 3 (frasi), 4 (sezioni)", "Livelli I, V, II, IV secondo le funzioni armoniche"], a: 1, fb: "I 4 livelli schenkeriani: Livello 4 (Vordergrund) = superficie: tutti gli accordi misura per misura. Livello 3 (Mittelgrund vicino): funzioni armoniche principali. Livello 2 (Mittelgrund profondo): regioni tonali e prolungazioni. Livello 1 (Hintergrund): solo Urlinie + Bassbrechung. Ogni riduzione rivela uno strato di significato strutturale." },
  { q: "Che cos'è il 'Vordergrund' nell'analisi schenkeriana?", opts: ["La struttura più profonda", "Il primo piano — la superficie musicale con tutti i suoi dettagli: melodia, accordi, ornamenti, ritmo", "La parte di pianoforte del primo piano", "Il motivo principale"], a: 0, fb: "Vordergrund = 'primo piano' = la superficie musicale completa così come viene eseguita. Tutto ciò che si sente: ornamenti, note di passaggio, arpeggi, note di bordatura, ritardi, appoggiature. È il punto di partenza dell'analisi — si riduce poi per scoprire i livelli più profondi." },
  { q: "Che cos'è l'Hintergrund nell'analisi schenkeriana?", opts: ["Lo sfondo orchestrale", "Lo sfondo strutturale — il livello più profondo: Urlinie + Bassbrechung. L'ossatura armonica sotto tutta l'ornamentazione di superficie", "Solo la parte del basso", "La forma complessiva (sonata, rondò)"], a: 1, fb: "Hintergrund = 'sfondo' = la struttura fondamentale. È l'Ursatz: la linea melodica discendente (Urlinie, dal 5°, 3° o 8° grado alla tonica) sorretta dal basso arpeggiato I–V–I. Questo livello rivela come tutta la complessità superficiale sia un'ornamentazione di una struttura armonica semplice." },
  { q: "Qual è il significato del simbolo 5̂ (accento circonflesso sul numero 5) nella notazione schenkeriana?", opts: ["Il 5° accordo del ciclo delle quinte", "Il 5° grado scalare come nota della Urlinie — frequente punto di partenza della linea strutturale discendente", "La 5ª misura dell'opera", "L'accordo di dominante"], a: 1, fb: "La notazione ̂ (cappello/accento) indica un grado scalare strutturale della Urlinie. 5̂ = il 5° grado scalare come nota iniziale della linea fondamentale. La Urlinie inizia tipicamente su 5̂, 3̂ o 8̂ e discende per gradi congiunti fino a 1̂ (tonica). 5̂–4̂–3̂–2̂–1̂ è la Urlinie a 5 note più completa." },
  { q: "Che cos'è una 'nota di bordatura' (Nebennote) nell'analisi schenkeriana?", opts: ["Una nota aggiunta per virtuosismo pianistico", "Un abbellimento che si allontana di un grado verso l'alto o verso il basso da una nota strutturale, poi vi ritorna — la nota strutturale 'circonda' l'ornamento", "Una nota appartenente al controsoggetto di una fuga", "Una nota cromatica"], a: 1, fb: "La nota di bordatura (Nebennote) è un'ornamentazione: la nota strutturale si sposta al grado adiacente (superiore o inferiore) e ritorna. Do–Re–Do: il Re è una bordatura superiore del Do strutturale. Nella riduzione schenkeriana, le note di bordatura scompaiono ai livelli più profondi per rivelare la nota strutturale." },
  { q: "Che cos'è una 'nota di passaggio' (Durchgangsnote) nell'analisi schenkeriana?", opts: ["Una nota che modifica il tempo", "Una nota che riempie lo spazio tra due note strutturali, generalmente per moto congiunto", "Una nota suonata fortissimo", "Una nota del controsoggetto"], a: 1, fb: "La nota di passaggio (Durchgangsnote) collega due note strutturali per moto congiunto: Do–Re–Mi, se Do e Mi sono strutturali, Re è una nota di passaggio. Nella riduzione, le note di passaggio scompaiono per rivelare la connessione diretta tra le note strutturali. Creano il movimento melodico di superficie." },
  { q: "Heinrich Schenker era un compositore o un teorico?", opts: ["Solo compositore (nessuna teoria)", "Principalmente teorico e critico musicale — compose poco ma sviluppò la più grande teoria analitica del XX secolo", "Un virtuoso pianista senza teoria", "Un allievo di Brahms che non pubblicò alcun testo"], a: 1, fb: "Heinrich Schenker (1868–1935) fu teorico, critico musicale e insegnante viennese. Studiò con Brahms e sviluppò la sua teoria analitica in diverse opere monumentali: Harmonielehre (1906), Contrappunto (1910–1922) e Der freie Satz (1935, postumo). Il suo metodo analitico è insegnato nelle università di tutto il mondo." },
  { q: "Perché l'analisi schenkeriana è talvolta criticata?", opts: ["Perché è troppo semplice", "Perché si applica con difficoltà alla musica non tonale (atonale, modale) e perché le sue 'leggi' a volte riflettono il gusto personale di Schenker più che una verità universale", "Perché si adatta solo a Bach", "Perché è troppo quantitativa e matematica"], a: 1, fb: "L'analisi schenkeriana ha dei limiti: 1/ Si applica solo alla musica tonale (non atonale o modale). 2/ Le scelte di riduzione sono a volte soggettive. 3/ Schenker stesso aveva gusti estetici marcati (adorava Brahms, detestava Debussy) che influenzavano le sue analisi. Queste critiche non diminuiscono la potenza dello strumento per la musica tonale." },
  { q: "Qual è la formula di Urlinie più frequente nei brani tonali brevi?", opts: ["8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (ottava completa)", "3̂–2̂–1̂ (linea discendente dalla terza alla tonica)", "5̂–4̂–3̂ (discesa parziale)", "1̂–2̂–1̂ (bordatura di tonica)"], a: 1, fb: "La Urlinie 3̂–2̂–1̂ è la più frequente nei brani brevi e semplici: la melodia strutturale scende dal 3° grado (mediante) alla tonica passando per la sopratonica. È la Urlinie di molti preludi di Bach, melodie folkloriche e brevi pezzi classici. La Urlinie 5̂–1̂ è più ampia, tipica di sonate e sinfonie." },
  { q: "Che cos'è il 'Kopfton' nell'analisi schenkeriana?", opts: ["La nota più acuta dell'opera", "La nota iniziale della Urlinie — il punto da cui la linea melodica strutturale scende verso la tonica", "Il primo accordo dell'esposizione", "La nota perno di una modulazione"], a: 1, fb: "Kopfton = 'nota testa'. È la nota iniziale della Urlinie, di solito 3̂, 5̂ o 8̂. Tutta la musica può essere vista come l'elaborazione del percorso tra il Kopfton e la tonica finale (1̂). Identificare il Kopfton è un passo fondamentale dell'analisi — determina quale versione della Urlinie è in gioco e come la melodia di superficie 'discende' strutturalmente." },
  { q: "Come aiuta la riduzione schenkeriana a capire una modulazione?", opts: ["Mostra che tutte le modulazioni sono false", "Rivela se la modulazione è strutturale (cambia il livello 2) o di superficie (ornamentale, cambiamento temporaneo che ritorna allo stesso livello 1)", "Elimina le modulazioni dall'analisi", "Trasforma tutte le modulazioni in prestiti modali"], a: 1, fb: "La riduzione schenkeriana distingue la modulazione strutturale (il livello 2 cambia regione tonale — il Mittelgrund si modifica) dalla modulazione di superficie (ornamentale — il livello 1 ritorna allo stesso Hintergrund). Molte modulazioni apparenti in Beethoven o Mozart sono in realtà prolungazioni ornamentali che ritornano alla tonalità iniziale senza cambiare la struttura profonda." },
  { q: "Qual è il motivo di base della 5ª Sinfonia di Beethoven op. 67?", opts: ["Do–Re–Mi–Fa (scala ascendente di 4 note)", "Sol–Sol–Sol–Mib (3 crome + semiminima: ritmo corto-corto-corto-lungo)", "Fa–Mi–Re–Do (scala discendente)", "La–Sol–Fa–Mi (tetracordo discendente)"], a: 1, fb: "Il motivo iniziale della 5ª Sinfonia è Sol–Sol–Sol–Mib — 3 crome + 1 semiminima (il ritmo «ta-ta-ta-TUM»). Questo motivo di 4 note non è solo un tema introduttivo: è il materiale generatore dell'intera opera. Beethoven lo trasforma, lo aumenta, lo inverte e lo frammenta nei 4 movimenti. È il motivo più famoso di tutta la letteratura musicale." },
  { q: "Come viene trasformato il motivo Sol–Sol–Sol–Mib nel 2° movimento della 5ª Sinfonia?", opts: ["Scompare completamente", "Viene trasformato in modo maggiore con un profilo melodico diverso ma conservando il ritmo corto-corto-corto-lungo", "Viene suonato identicamente ma trasportato", "Viene invertito melodicamente"], a: 1, fb: "Nel 2° movimento (Andante con moto), il motivo ritmico corto-corto-corto-lungo è conservato ma integrato in una melodia lirica maggiore molto diversa dalla brutalità del 1° movimento. Il profilo melodico cambia, ma l'identità ritmica permette di riconoscere il motivo trasformato. Beethoven mostra che il motivo trascende le sue qualità superficiali." },
  { q: "Che cos'è la 'frammentazione' di un motivo?", opts: ["Sopprimere completamente il motivo", "Ridurre il motivo a uno dei suoi elementi costitutivi — suonare solo il ritmo, o solo le prime 2 note, per creare tensione o attesa", "Suonare il motivo in aumentazione", "Combinare due motivi diversi"], a: 1, fb: "La frammentazione scompone il motivo nei suoi elementi. Nella 5ª Sinfonia, sviluppo del 1° movimento, Beethoven frammenta il motivo a una singola quarta (Sol–Mib), poi a una singola semiminima (solo ritmo, nessuna melodia). Questa riduzione progressiva crea una tensione estrema — il motivo è 'lacerato' prima di essere riassemblato nella riesposizione." },
  { q: "Che cos'è la 'sequenza' motivica come tecnica di sviluppo?", opts: ["Ripetere il motivo alla stessa altezza", "Ripetere il motivo trasponendolo a intervalli regolari — lo stesso profilo melodico e ritmico sale o scende per gradi", "Invertire il motivo melodicamente", "Aumentare la durata di tutte le note"], a: 1, fb: "La sequenza è la ripetizione di un motivo trasposto a intervalli regolari. Motivo su Do, poi su Si, poi su La (sequenza discendente per gradi). La sequenza crea un forte movimento direzionale — 'trascina' la musica verso un obiettivo. Bach, Handel, Vivaldi e Beethoven la usano massicciamente nelle transizioni e negli sviluppi." },
  { q: "Qual è il 'motivo generatore' nei Quartetti d'archi di Brahms op. 51?", opts: ["Una terza maggiore ascendente", "Un intervallo di seconda (spesso minore) che si ritrova in tutte le forme (ascendente, discendente, aumentato, invertito) in tutta l'opera", "Un ritmo di tre crome", "Un accordo di settima diminuita"], a: 1, fb: "Nell'op. 51 di Brahms, un intervallo di seconda struttura ogni movimento. L'analisi rivela che lo stesso intervallo (Sol–Lab, ad esempio) riappare ovunque: nel soggetto principale, nel controsoggetto, nella melodia del 2° movimento, nello scherzo. È l''economia motivica' di Brahms — comporre il massimo con il minimo di materiale." },
  { q: "Come trasforma Beethoven il motivo della 5ª Sinfonia nel 4° movimento finale?", opts: ["Lo elimina per terminare con un nuovo tema", "Lo presenta trionfalmente in maggiore, aumentato e glorificato — la 'vittoria' dalla tonalità minore verso la maggiore", "Lo suona esattamente come all'inizio", "Lo inverte melodicamente"], a: 1, fb: "Il 4° movimento (Allegro, Do maggiore) è la 'risposta' al 1° (Do minore). Il motivo Sol–Sol–Sol–Mib, prima oscuro e minaccioso, diventa trionfante in maggiore con gli ottoni a piena potenza. La trasformazione modale (minore → maggiore) e dinamica (forte drammatico → fortissimo vittorioso) significa la risoluzione del conflitto dell'intera sinfonia." },
  { q: "Che cos'è l'analisi della 'condotta delle voci' in un contesto analitico (non compositivo)?", opts: ["Identificare le voci di una fuga", "Tracciare come ogni voce di un accordo si sposta verso le note dell'accordo seguente — identificare moti congiunti, salti, note tenute e note comuni", "Analizzare la tessitura dei cantanti", "Contare il numero di voci in una fuga"], a: 1, fb: "L'analisi della condotta delle voci segue ogni singola linea in una progressione armonica. In un I–IV–V–I, come si muove il soprano? Il contralto? Il basso? Si tracciano le note comuni (legate), i moti congiunti (fluidi) e i salti. Questa analisi rivela la logica lineare sottostante alla progressione armonica." },
  { q: "Qual è il metodo in 4 passi per eseguire un'analisi schenkeriana di un brano?", opts: ["1-Ascoltare 2-Suonare 3-Memorizzare 4-Interpretare", "1-Identificare le cadenze strutturali 2-Tracciare il basso strutturale 3-Identificare le note melodiche strutturali 4-Ridurre progressivamente fino all'Ursatz", "1-Analizzare gli accordi 2-Nominare le funzioni 3-Identificare la tonalità 4-Scrivere il riassunto", "1-Identificare il soggetto 2-La risposta 3-Il controsoggetto 4-Gli episodi"], a: 1, fb: "Il metodo analitico schenkeriano: 1/ Identificare le cadenze strutturali (V→I autentiche) che delimitano le sezioni; 2/ Tracciare la linea del basso strutturale (fondamentali delle armonie importanti); 3/ Identificare le note melodiche strutturali (note tenute lunghe, note cadenzali); 4/ Ridurre progressivamente fino all'Ursatz semplice." },
  { q: "Come distingue la notazione schenkeriana le note strutturali dalle note ornamentali?", opts: ["Per il colore delle note (nere vs bianche)", "Tramite l'uso di teste di nota con gambetti (note strutturali) vs senza gambetti (ornamentali), più legature per le prolungazioni", "Per la posizione sul pentagramma (basse vs acute)", "Per la cifra romana (I, V) vs araba (1, 2)"], a: 1, fb: "La notazione schenkeriana usa un sistema grafico specifico: note strutturali = teste di nota con gambetti; note ornamentali = senza gambetto o di piccole dimensioni; legature curve = prolungazioni armoniche; legature melodiche = connessioni tra note strutturali. Il sistema visivo rivela la gerarchia analitica a colpo d'occhio." },
  { q: "Perché l'analisi motivica della 5ª Sinfonia è più informativa dell'analisi accordo per accordo?", opts: ["L'analisi degli accordi è più rapida da eseguire", "L'analisi motivica rivela la coerenza architettonica su 4 movimenti — come un singolo motivo di 4 note struttura 35 minuti di musica, cosa che un'analisi misura per misura non può mostrare", "L'analisi motivica è meno precisa ma più artistica", "Entrambe le analisi forniscono esattamente le stesse informazioni"], a: 1, fb: "L'analisi accordo per accordo descrive la superficie armonica di ogni misura ma non rivela come queste misure siano collegate. L'analisi motivica mostra la coerenza: il motivo Sol–Sol–Sol–Mib ritorna in 15 forme diverse in 35 minuti. Questa profonda unità strutturale è ciò che rende la 5ª Sinfonia un'opera unificata piuttosto che una raccolta di temi." },
  { q: "Che cos'è la 'diminuzione' di un motivo come tecnica di sviluppo?", opts: ["Suonare il motivo più piano (diminuendo)", "Suonare il motivo in valori ritmici ridotti — ogni semiminima diventa croma, ogni croma diventa semicroma", "Ridurre il numero di note del motivo", "Trasportare il motivo più in basso"], a: 1, fb: "La diminuzione è il contrario dell'aumentazione: il motivo viene suonato in valori ritmici ridotti. Un motivo di semiminime diventa crome, le crome diventano semicrome. L'effetto è accelerare e alleggerire il motivo — creare agitazione o brillantezza dove l'aumentazione crea gravità. Usata negli sviluppi per accelerare progressivamente." },
  { q: "Che cosa apporta l'analisi motivica rispetto all'analisi formale (sonata, rondò)?", opts: ["L'analisi formale è più completa — sostituisce l'analisi motivica", "L'analisi formale descrive la struttura esterna (A-B-A, esposizione-sviluppo-riesposizione); l'analisi motivica rivela la sostanza interna (come un motivo genera il contenuto di ogni sezione)", "Sono identiche e intercambiabili", "L'analisi motivica si applica solo ai brani moderni"], a: 1, fb: "L'analisi formale identifica le 'caselle' della forma: esposizione, sviluppo, riesposizione, coda. L'analisi motivica riempie queste caselle di significato: cosa viene sviluppato nello sviluppo (quali motivi, quali trasformazioni), perché la riesposizione differisce dall'esposizione (quali motivi si sono evoluti). Le due analisi sono complementari — nessuna da sola è sufficiente." },
];

const questionsPt: Question[] = [
  { q: "O que é o Ursatz segundo Heinrich Schenker?", opts: ["Um motivo de 4 notas em uma fuga", "A estrutura harmônica fundamental de toda a música tonal: Urlinie (linha melódica descendente 5̂–1̂) + Bassbrechung (arpejo do baixo I–V–I)", "O acorde de tônica em uma cadência", "O primeiro tema de uma forma sonata"], a: 1, fb: "O Ursatz ('estrutura fundamental') é a armação harmônica de toda a música tonal segundo Schenker. Compreende a Urlinie (linha melódica descendente do 5.°, 3.° ou 8.° grau até a tônica) e o Bassbrechung (baixo que arpeja I–V–I). Todo o restante da música é 'prolongação' ou 'ornamento' desse Ursatz subjacente." },
  { q: "O que é a 'prolongação harmônica' na análise schenkeriana?", opts: ["Aumentar a duração de um acorde", "A elaboração de uma harmonia estrutural por harmonias intermediárias — a tônica 'persiste' harmonicamente mesmo quando acordes não-tônicos a decoram temporariamente", "Um pedal de baixo", "Um tremolo sobre um acorde"], a: 1, fb: "A prolongação significa que uma harmonia estrutural (geralmente I ou V) continua a exercer sua influência enquanto harmonias de passagem ou ornamentos a decoram na superfície. Em 32 compassos aparentemente variados, a análise pode mostrar que a tônica está 'prolongada' — as mudanças de superfície não alteram a estrutura profunda." },
  { q: "Quais são os 4 níveis de redução na análise schenkeriana?", opts: ["Nível A (maior), B (menor), C (cromático), D (diatônico)", "Nível 4 (superfície, todos os acordes), 3 (intermediário), 2 (regiões tonais), 1 (Urlinie/estrutura)", "Nível 1 (notas), 2 (compassos), 3 (frases), 4 (seções)", "Níveis I, V, II, IV segundo as funções harmônicas"], a: 1, fb: "Os 4 níveis schenkerianos: Nível 4 (Vordergrund) = superfície: todos os acordes compasso por compasso. Nível 3 (Mittelgrund próximo): funções harmônicas principais. Nível 2 (Mittelgrund profundo): regiões tonais e prolongações. Nível 1 (Hintergrund): apenas Urlinie + Bassbrechung. Cada redução revela uma camada de significado estrutural." },
  { q: "O que é o 'Vordergrund' na análise schenkeriana?", opts: ["A estrutura mais profunda", "O primeiro plano — a superfície musical com todos os seus detalhes: melodia, acordes, ornamentos, ritmo", "A parte de piano do primeiro plano", "O motivo principal"], a: 0, fb: "Vordergrund = 'primeiro plano' = a superfície musical completa tal como é executada. Tudo o que se ouve: ornamentos, notas de passagem, arpejos, notas de bordadura, retardos, apojaturas. É o ponto de partida da análise — reduz-se em seguida para descobrir os níveis mais profundos." },
  { q: "O que é o 'Hintergrund' na análise schenkeriana?", opts: ["O fundo orquestral", "O fundo estrutural — o nível mais profundo: Urlinie + Bassbrechung. A armação harmônica sob toda a ornamentação de superfície", "Apenas a parte do baixo", "A forma global (sonata, rondó)"], a: 1, fb: "Hintergrund = 'fundo' = a estrutura fundamental. É o Ursatz: a linha melódica descendente (Urlinie, do 5.°, 3.° ou 8.° grau até a tônica) sustentada pelo baixo arpejado I–V–I. Este nível revela como toda a complexidade de superfície é uma ornamentação de uma estrutura harmônica simples." },
  { q: "Qual é o significado do símbolo 5̂ (chapéu sobre o número 5) na notação schenkeriana?", opts: ["O 5.° acorde do ciclo de quintas", "O 5.° grau da escala como nota da Urlinie — ponto de partida frequente da linha estrutural descendente", "O 5.° compasso da obra", "O acorde de dominante"], a: 1, fb: "A notação ̂ (acento circunflexo) indica um grau escalar estrutural da Urlinie. 5̂ = o 5.° grau da escala como nota inicial da linha fundamental. A Urlinie tipicamente começa em 5̂, 3̂ ou 8̂ e desce por graus conjuntos até 1̂ (tônica). 5̂–4̂–3̂–2̂–1̂ é a Urlinie de 5 notas mais completa." },
  { q: "O que é uma 'nota de bordadura' (Nebennote) na análise schenkeriana?", opts: ["Uma nota acrescentada para virtuosismo pianístico", "Um ornamento que se afasta de uma nota estrutural um grau para cima ou para baixo, depois retorna — a nota estrutural 'envolve' o ornamento", "Uma nota pertencente ao contrassujeito de uma fuga", "Uma nota cromática"], a: 1, fb: "A nota de bordadura (Nebennote) é uma ornamentação: a nota estrutural parte para o grau adjacente (superior ou inferior) e retorna. Dó–Ré–Dó: o Ré é uma bordadura superior do Dó estrutural. Na redução schenkeriana, as notas de bordadura desaparecem nos níveis mais profundos para revelar a nota estrutural." },
  { q: "O que é uma 'nota de passagem' (Durchgangsnote) na análise schenkeriana?", opts: ["Uma nota que modifica o andamento", "Uma nota que preenche o espaço entre duas notas estruturais, geralmente por movimento conjunto", "Uma nota tocada fortissimo", "Uma nota do contrassujeito"], a: 1, fb: "A nota de passagem (Durchgangsnote) conecta duas notas estruturais por movimento conjunto: Dó–Ré–Mi, se Dó e Mi são estruturais, Ré é uma nota de passagem. Na redução, as notas de passagem desaparecem para revelar a conexão direta entre as notas estruturais. Elas criam o movimento melódico de superfície." },
  { q: "Heinrich Schenker era compositor ou teórico?", opts: ["Apenas compositor (nenhuma teoria)", "Principalmente teórico e crítico musical — compôs pouco mas desenvolveu a maior teoria analítica do século XX", "Um intérprete virtuoso de piano sem teoria", "Um aluno de Brahms que não publicou nenhum texto"], a: 1, fb: "Heinrich Schenker (1868–1935) foi teórico, crítico musical e professor vienense. Estudou com Brahms e desenvolveu sua teoria analítica em várias obras monumentais: Harmonielehre (1906), Counterpoint (1910–1922) e Der freie Satz (1935, póstumo). Seu método analítico é ensinado em universidades do mundo inteiro." },
  { q: "Por que a análise schenkeriana é às vezes criticada?", opts: ["Porque é simples demais", "Porque se aplica com dificuldade à música não tonal (atonal, modal) e porque suas 'leis' às vezes refletem o gosto pessoal de Schenker mais do que uma verdade universal", "Porque só serve para Bach", "Porque é quantitativa e matemática demais"], a: 1, fb: "A análise schenkeriana tem limites: 1/ Aplica-se apenas à música tonal (não atonal nem modal). 2/ As escolhas de redução são às vezes subjetivas. 3/ O próprio Schenker tinha gostos estéticos marcados (adorava Brahms, detestava Debussy) que influenciavam suas análises. Essas críticas não diminuem o poder da ferramenta para a música tonal." },
  { q: "Qual é a fórmula de Urlinie mais frequente nas peças tonais curtas?", opts: ["8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (oitava completa)", "3̂–2̂–1̂ (linha descendente da terça até a tônica)", "5̂–4̂–3̂ (descida parcial)", "1̂–2̂–1̂ (bordadura de tônica)"], a: 1, fb: "A Urlinie 3̂–2̂–1̂ é a mais frequente em peças curtas e simples: a melodia estrutural desce do 3.° grau (mediante) até a tônica passando pela supertônica. É a Urlinie de muitos prelúdios de Bach, melodias folclóricas e peças clássicas curtas. A Urlinie 5̂–1̂ é mais ampla, típica de sonatas e sinfonias." },
  { q: "O que é o 'Kopfton' na análise schenkeriana?", opts: ["A nota mais aguda da obra", "A nota inicial da Urlinie — o ponto a partir do qual a linha melódica estrutural desce até a tônica", "O primeiro acorde da exposição", "A nota pivô de uma modulação"], a: 1, fb: "Kopfton = 'nota cabeça'. É a nota inicial da Urlinie, geralmente 3̂, 5̂ ou 8̂. Toda a música pode ser vista como a elaboração do percurso entre o Kopfton e a tônica final (1̂). Identificar o Kopfton é um passo fundamental da análise — determina qual versão da Urlinie está em jogo e como a melodia de superfície 'desce' estruturalmente." },
  { q: "Como a redução schenkeriana ajuda a compreender uma modulação?", opts: ["Mostra que todas as modulações são falsas", "Revela se a modulação é estrutural (muda o nível 2) ou de superfície (ornamental, mudança temporária que retorna ao mesmo nível 1)", "Elimina as modulações da análise", "Transforma todas as modulações em empréstimos modais"], a: 1, fb: "A redução schenkeriana distingue a modulação estrutural (o nível 2 muda de região tonal — o Mittelgrund é modificado) da modulação de superfície (ornamental — o nível 1 retorna ao mesmo Hintergrund). Muitas modulações aparentes em Beethoven ou Mozart são na verdade prolongações ornamentais que retornam à tonalidade inicial sem alterar a estrutura profunda." },
  { q: "Qual é o motivo básico da 5ª Sinfonia de Beethoven op. 67?", opts: ["Dó–Ré–Mi–Fá (escala ascendente de 4 notas)", "Sol–Sol–Sol–Mib (3 colcheias + semínima: ritmo curto-curto-curto-longo)", "Fá–Mi–Ré–Dó (escala descendente)", "Lá–Sol–Fá–Mi (tetracorde descendente)"], a: 1, fb: "O motivo inicial da 5ª Sinfonia é Sol–Sol–Sol–Mib — 3 colcheias + 1 semínima (o ritmo «ta-ta-ta-TUM»). Este motivo de 4 notas não é apenas um tema introdutório: é o material gerador de toda a obra. Beethoven o transforma, aumenta, inverte e fragmenta ao longo dos 4 movimentos. É o motivo mais famoso de toda a literatura musical." },
  { q: "Como o motivo Sol–Sol–Sol–Mib é transformado no 2.° movimento da 5ª Sinfonia?", opts: ["Desaparece completamente", "É transformado em modo maior com um contorno melódico diferente, mas conservando o ritmo curto-curto-curto-longo", "É tocado identicamente mas transportado", "É invertido melodicamente"], a: 1, fb: "No 2.° movimento (Andante con moto), o motivo rítmico curto-curto-curto-longo é conservado mas integrado numa melodia lírica maior muito diferente da brutalidade do 1.° movimento. O contorno melódico muda, mas a identidade rítmica permite reconhecer o motivo transformado. Beethoven mostra que o motivo transcende suas qualidades superficiais." },
  { q: "O que é a 'fragmentação' de um motivo?", opts: ["Suprimir o motivo completamente", "Reduzir o motivo a um de seus elementos constitutivos — tocar apenas o ritmo, ou apenas as 2 primeiras notas, para criar tensão ou expectativa", "Tocar o motivo em aumentação", "Combinar dois motivos diferentes"], a: 1, fb: "A fragmentação decompõe o motivo em seus elementos. Na 5ª Sinfonia, desenvolvimento do 1.° movimento, Beethoven fragmenta o motivo a uma única quarta (Sol–Mib), depois a uma única semínima (apenas o ritmo, sem melodia). Essa redução progressiva cria uma tensão extrema — o motivo é 'despedaçado' antes de ser remontado na reexposição." },
  { q: "O que é a 'sequência' motivica como técnica de desenvolvimento?", opts: ["Repetir o motivo na mesma altura", "Repetir o motivo transpondo-o a intervalos regulares — o mesmo contorno melódico e rítmico sobe ou desce por graus", "Inverter o motivo melodicamente", "Aumentar a duração de todas as notas"], a: 1, fb: "A sequência é a repetição de um motivo transposto a intervalos regulares. Motivo em Dó, depois em Si, depois em Lá (sequência descendente por graus). A sequência cria um forte movimento direcional — 'puxa' a música em direção a um alvo. Bach, Handel, Vivaldi e Beethoven a usam massivamente nas transições e nos desenvolvimentos." },
  { q: "Qual é o 'motivo gerador' nos Quartetos de cordas de Brahms op. 51?", opts: ["Uma terça maior ascendente", "Um intervalo de segunda (frequentemente menor) que se encontra em todas as formas (ascendente, descendente, aumentado, invertido) ao longo de toda a obra", "Um ritmo de três colcheias", "Um acorde de sétima diminuta"], a: 1, fb: "No op. 51 de Brahms, um intervalo de segunda estrutura cada movimento. A análise revela que o mesmo intervalo (Sol–Láb, por exemplo) reaparece em toda parte: no tema principal, no contrassujeito, na melodia do 2.° movimento, no scherzo. É a 'economia motivica' de Brahms — compor o máximo com o mínimo de material." },
  { q: "Como Beethoven transforma o motivo da 5ª Sinfonia no 4.° movimento final?", opts: ["Elimina-o para terminar com um tema novo", "Apresenta-o triunfalmente em maior, aumentado e glorificado — a 'vitória' da tonalidade menor para a maior", "Toca-o exatamente como no início", "Inverte-o melodicamente"], a: 1, fb: "O 4.° movimento (Allegro, Dó maior) é a 'resposta' ao 1.° (Dó menor). O motivo Sol–Sol–Sol–Mib, antes escuro e ameaçador, torna-se triunfante em maior com os metais em plena potência. A transformação modal (menor → maior) e dinâmica (forte dramático → fortissimo vitorioso) significa a resolução do conflito de toda a sinfonia." },
  { q: "O que é a análise de 'condução de vozes' em um contexto analítico (não compositivo)?", opts: ["Identificar as vozes de uma fuga", "Rastrear como cada voz de um acorde se move para as notas do acorde seguinte — identificar movimentos conjuntos, saltos, notas sustentadas e notas comuns", "Analisar a tessitura dos cantores", "Contar o número de vozes em uma fuga"], a: 1, fb: "A análise de condução de vozes acompanha cada linha individual numa progressão harmônica. Num I–IV–V–I, como se move o soprano? O contralto? O baixo? Traçam-se as notas comuns (ligadas), os movimentos conjuntos (fluidos) e os saltos. Essa análise revela a lógica linear subjacente à progressão harmônica." },
  { q: "Qual é o método de 4 etapas para realizar uma análise schenkeriana de uma peça?", opts: ["1-Ouvir 2-Tocar 3-Memorizar 4-Interpretar", "1-Identificar as cadências estruturais 2-Traçar o baixo estrutural 3-Identificar as notas melódicas estruturais 4-Reduzir progressivamente até o Ursatz", "1-Analisar os acordes 2-Nomear as funções 3-Identificar a tonalidade 4-Escrever o resumo", "1-Identificar o sujeito 2-A resposta 3-O contrassujeito 4-Os episódios"], a: 1, fb: "O método analítico schenkeriano: 1/ Identificar as cadências estruturais (V→I autênticas) que delimitam as seções; 2/ Traçar a linha do baixo estrutural (fundamentais das harmonias importantes); 3/ Identificar as notas melódicas estruturais (notas sustentadas longas, notas cadenciais); 4/ Reduzir progressivamente até o Ursatz simples." },
  { q: "Como a notação schenkeriana distingue notas estruturais de notas ornamentais?", opts: ["Pela cor das notas (pretas vs brancas)", "Pelo uso de cabeças de nota com hastes (notas estruturais) vs sem hastes (ornamentais), mais ligaduras para as prolongações", "Pela posição na pauta (graves vs agudas)", "Pela cifra romana (I, V) vs arábica (1, 2)"], a: 1, fb: "A notação schenkeriana usa um sistema gráfico específico: notas estruturais = cabeças de nota com hastes; notas ornamentais = sem haste ou em tamanho pequeno; ligaduras curvas = prolongações harmônicas; ligaduras melódicas = conexões entre notas estruturais. O sistema visual revela a hierarquia analítica num relance." },
  { q: "Por que a análise motivica da 5ª Sinfonia é mais informativa do que a análise acorde por acorde?", opts: ["A análise de acordes é mais rápida de realizar", "A análise motivica revela a coerência arquitetônica ao longo de 4 movimentos — como um único motivo de 4 notas estrutura 35 minutos de música, algo que uma análise compasso a compasso não pode mostrar", "A análise motivica é menos precisa mas mais artística", "As duas análises fornecem exatamente as mesmas informações"], a: 1, fb: "A análise acorde por acorde descreve a superfície harmônica de cada compasso mas não revela como esses compassos estão conectados. A análise motivica mostra a coerência: o motivo Sol–Sol–Sol–Mib retorna em 15 formas diferentes em 35 minutos. Essa profunda unidade estrutural é o que faz da 5ª Sinfonia uma obra unificada e não uma coleção de temas." },
  { q: "O que é a 'diminuição' de um motivo como técnica de desenvolvimento?", opts: ["Tocar o motivo mais suavemente (diminuendo)", "Tocar o motivo em valores rítmicos reduzidos — cada semínima torna-se colcheia, cada colcheia torna-se semicolcheia", "Reduzir o número de notas do motivo", "Transportar o motivo mais abaixo"], a: 1, fb: "A diminuição é o oposto da aumentação: o motivo é tocado em valores rítmicos reduzidos. Um motivo de semínimas torna-se colcheias, as colcheias tornam-se semicolcheias. O efeito é acelerar e aligeirar o motivo — criar agitação ou brilhantismo onde a aumentação cria gravidade. Usada nos desenvolvimentos para acelerar progressivamente." },
  { q: "O que a análise motivica contribui em relação à análise formal (sonata, rondó)?", opts: ["A análise formal é mais completa — substitui a análise motivica", "A análise formal descreve a estrutura externa (A-B-A, exposição-desenvolvimento-reexposição); a análise motivica revela a substância interna (como um motivo gera o conteúdo de cada seção)", "São idênticas e intercambiáveis", "A análise motivica só se aplica a peças modernas"], a: 1, fb: "A análise formal identifica as 'caixas' da forma: exposição, desenvolvimento, reexposição, coda. A análise motivica preenche essas caixas de significado: o que é desenvolvido no desenvolvimento (quais motivos, quais transformações), por que a reexposição difere da exposição (quais motivos evoluíram). As duas análises são complementares — nenhuma é suficiente sozinha." },
];

